SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Total internal reflection can occur when light travels from:", "explanation": "Total internal reflection occurs only when light travels from a denser medium (higher refractive index) to a rarer medium (lower refractive index) and the angle of incidence exceeds the critical angle. It cannot occur when light goes from a rarer to a denser medium.", "correct_answer": "B", "concept_tags": ["total-internal-reflection", "denser-rarer-medium", "critical-angle"], "payload": {"question_id": "cuet-phy-ray-prism-01", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "A rarer medium to a denser medium", "is_correct": false}, {"key": "B", "text": "A denser medium to a rarer medium", "is_correct": true}, {"key": "C", "text": "Any medium to any other medium", "is_correct": false}, {"key": "D", "text": "Vacuum to any material medium", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "When light goes from rarer to denser medium, it bends towards the normal and can never reach the critical angle for TIR.", "misconception": "Reversing the condition for total internal reflection"}, {"option_key": "C", "hint": "TIR does not occur in all cases; it requires light to go from a denser to a rarer medium at an angle greater than the critical angle.", "misconception": null}, {"option_key": "D", "hint": "Vacuum has the lowest refractive index (n = 1), so light cannot go from vacuum to a material medium and undergo TIR.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The critical angle for a medium of refractive index √2 is:", "explanation": "The critical angle C is given by sin C = 1/n. For n = √2, sin C = 1/√2, which gives C = 45°. At this angle, the refracted ray grazes along the surface of separation.", "correct_answer": "C", "concept_tags": ["critical-angle", "refractive-index", "total-internal-reflection"], "payload": {"question_id": "cuet-phy-ray-prism-02", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "30°", "is_correct": false}, {"key": "B", "text": "60°", "is_correct": false}, {"key": "C", "text": "45°", "is_correct": true}, {"key": "D", "text": "90°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "sin 30° = 0.5 = 1/2, which would correspond to n = 2, not √2.", "misconception": "Using wrong value of refractive index"}, {"option_key": "B", "hint": "sin 60° = √3/2 ≈ 0.866, which gives n = 2/√3 ≈ 1.155, not √2.", "misconception": null}, {"option_key": "D", "hint": "A critical angle of 90° would mean sin C = 1, giving n = 1, which corresponds to vacuum — not a medium with n = √2.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following phenomena is responsible for the formation of a mirage in deserts?", "explanation": "Mirages in deserts are caused by total internal reflection. The air near the hot ground is less dense (lower refractive index) than the cooler air above. Light from distant objects travelling downward through layers of progressively rarer air gets totally internally reflected, creating an illusion of water on the ground.", "correct_answer": "A", "concept_tags": ["mirage", "total-internal-reflection", "atmospheric-refraction"], "payload": {"question_id": "cuet-phy-ray-prism-03", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "Total internal reflection", "is_correct": true}, {"key": "B", "text": "Diffraction", "is_correct": false}, {"key": "C", "text": "Interference", "is_correct": false}, {"key": "D", "text": "Polarisation", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Diffraction involves bending of light around obstacles and does not explain the inverted image seen in mirages.", "misconception": null}, {"option_key": "C", "hint": "Interference involves superposition of coherent light waves and produces fringe patterns, not mirage-like effects.", "misconception": null}, {"option_key": "D", "hint": "Polarisation deals with the orientation of the electric field vector and does not cause visual illusions like mirages.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In the visible spectrum, which colour of light is deviated the most by a glass prism?", "explanation": "Violet light has the shortest wavelength among visible colours and hence the highest refractive index in glass. Since deviation increases with refractive index, violet light is deviated the most by a glass prism. Red light, having the longest wavelength, is deviated the least.", "correct_answer": "D", "concept_tags": ["dispersion", "prism", "deviation", "violet-light"], "payload": {"question_id": "cuet-phy-ray-prism-04", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "Red", "is_correct": false}, {"key": "B", "text": "Yellow", "is_correct": false}, {"key": "C", "text": "Green", "is_correct": false}, {"key": "D", "text": "Violet", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Red light has the longest wavelength and therefore the lowest refractive index in glass, resulting in the least deviation.", "misconception": "Confusing maximum and minimum deviation colours"}, {"option_key": "B", "hint": "Yellow lies in the middle of the visible spectrum and experiences moderate deviation, not the maximum.", "misconception": null}, {"option_key": "C", "hint": "Green, like yellow, is in the middle of the spectrum and does not experience the maximum deviation.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A ray of light passes through an equilateral prism such that the angle of incidence equals the angle of emergence and each equals 60°. The angle of minimum deviation is:", "explanation": "For an equilateral prism, A = 60°. At minimum deviation, i = e. Using the prism formula δ = i + e − A, we get δ_min = 60° + 60° − 60° = 60°. Also, at minimum deviation i = (A + δ_min)/2 = (60° + 60°)/2 = 60°, which is consistent.", "correct_answer": "B", "concept_tags": ["prism", "minimum-deviation", "equilateral-prism"], "payload": {"question_id": "cuet-phy-ray-prism-05", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "30°", "is_correct": false}, {"key": "B", "text": "60°", "is_correct": true}, {"key": "C", "text": "45°", "is_correct": false}, {"key": "D", "text": "90°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "30° would result if you incorrectly used δ = i − A/2 or some other wrong formula. The correct formula is δ = i + e − A.", "misconception": null}, {"option_key": "C", "hint": "45° does not follow from the prism formula with the given values of i, e, and A.", "misconception": null}, {"option_key": "D", "hint": "90° exceeds the angle of the prism and is far too large for this configuration.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Optical fibres work on the principle of:", "explanation": "Optical fibres use total internal reflection to transmit light signals over long distances with minimal loss. The fibre consists of a core with a higher refractive index surrounded by cladding with a lower refractive index, ensuring that light undergoes TIR repeatedly as it propagates through the fibre.", "correct_answer": "C", "concept_tags": ["optical-fibre", "total-internal-reflection", "applications"], "payload": {"question_id": "cuet-phy-ray-prism-06", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "Refraction", "is_correct": false}, {"key": "B", "text": "Diffraction", "is_correct": false}, {"key": "C", "text": "Total internal reflection", "is_correct": true}, {"key": "D", "text": "Scattering", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Simple refraction would cause light to exit the fibre at each boundary. TIR keeps the light confined within the core.", "misconception": "Confusing refraction with total internal reflection"}, {"option_key": "B", "hint": "Diffraction involves spreading of light around obstacles and has no role in guiding light through optical fibres.", "misconception": null}, {"option_key": "D", "hint": "Scattering disperses light in random directions and would cause signal loss, not signal transmission.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The refractive index of a prism material is √3 and the angle of the prism is 60°. The angle of minimum deviation is:", "explanation": "Using the prism formula: n = sin[(A + δ_min)/2] / sin(A/2). Substituting: √3 = sin[(60° + δ_min)/2] / sin 30° = sin[(60° + δ_min)/2] / 0.5. So sin[(60° + δ_min)/2] = √3/2, giving (60° + δ_min)/2 = 60°, hence δ_min = 60°.", "correct_answer": "A", "concept_tags": ["prism", "minimum-deviation", "refractive-index"], "payload": {"question_id": "cuet-phy-ray-prism-07", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "60°", "is_correct": true}, {"key": "B", "text": "45°", "is_correct": false}, {"key": "C", "text": "30°", "is_correct": false}, {"key": "D", "text": "90°", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Substituting δ_min = 45° gives sin(52.5°)/sin(30°) ≈ 0.793/0.5 = 1.586, which is not √3 ≈ 1.732.", "misconception": null}, {"option_key": "C", "hint": "Substituting δ_min = 30° gives sin(45°)/sin(30°) = (1/√2)/(1/2) = √2 ≈ 1.414, not √3.", "misconception": null}, {"option_key": "D", "hint": "δ_min = 90° gives sin(75°)/sin(30°) ≈ 0.966/0.5 = 1.932, which exceeds √3.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The dispersive power of a prism depends on:", "explanation": "Dispersive power ω = (n_v − n_r)/(n_y − 1), where n_v, n_r, and n_y are the refractive indices for violet, red, and yellow light respectively. It depends solely on the material of the prism (i.e., how much the refractive index varies with wavelength) and is independent of the angle of the prism.", "correct_answer": "D", "concept_tags": ["dispersive-power", "prism-material", "dispersion"], "payload": {"question_id": "cuet-phy-ray-prism-08", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "The angle of the prism only", "is_correct": false}, {"key": "B", "text": "The angle of incidence only", "is_correct": false}, {"key": "C", "text": "Both the angle of the prism and the material", "is_correct": false}, {"key": "D", "text": "The material of the prism only", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The angle of the prism affects the angular dispersion but not the dispersive power, which is a ratio independent of A.", "misconception": "Confusing angular dispersion with dispersive power"}, {"option_key": "B", "hint": "The angle of incidence affects the deviation but the dispersive power is a material property independent of the incident angle.", "misconception": null}, {"option_key": "C", "hint": "Although angular dispersion depends on A, the dispersive power ω = (n_v − n_r)/(n_y − 1) does not depend on the prism angle.", "misconception": "Confusing dispersive power with angular dispersion"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A thin prism of angle 6° produces a deviation of 3°. The refractive index of the prism material is:", "explanation": "For a thin prism, the deviation is given by δ = (n − 1)A. Substituting δ = 3° and A = 6°: 3 = (n − 1) × 6, so n − 1 = 0.5, giving n = 1.5.", "correct_answer": "B", "concept_tags": ["thin-prism", "deviation", "refractive-index"], "payload": {"question_id": "cuet-phy-ray-prism-09", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "1.33", "is_correct": false}, {"key": "B", "text": "1.5", "is_correct": true}, {"key": "C", "text": "2.0", "is_correct": false}, {"key": "D", "text": "1.6", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "n = 1.33 would give δ = (1.33 − 1) × 6 = 0.33 × 6 = 1.98°, not 3°.", "misconception": null}, {"option_key": "C", "hint": "n = 2.0 would give δ = (2.0 − 1) × 6 = 1 × 6 = 6°, not 3°.", "misconception": null}, {"option_key": "D", "hint": "n = 1.6 would give δ = (1.6 − 1) × 6 = 0.6 × 6 = 3.6°, which is close but not exactly 3°.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In the formation of a rainbow, the light undergoes:", "explanation": "A rainbow is formed when sunlight enters a water droplet, undergoes refraction at the surface, total internal reflection inside the droplet, and then refraction again as it exits. The dispersion during refraction splits white light into its component colours.", "correct_answer": "C", "concept_tags": ["rainbow", "refraction", "total-internal-reflection", "dispersion"], "payload": {"question_id": "cuet-phy-ray-prism-10", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "Only refraction", "is_correct": false}, {"key": "B", "text": "Only total internal reflection", "is_correct": false}, {"key": "C", "text": "Refraction, internal reflection and dispersion", "is_correct": true}, {"key": "D", "text": "Diffraction and interference", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Refraction alone cannot explain the formation of a rainbow; internal reflection inside the water droplet is essential to redirect light back towards the observer.", "misconception": null}, {"option_key": "B", "hint": "Total internal reflection alone cannot produce the spectrum of colours; refraction-induced dispersion is needed to separate the colours.", "misconception": null}, {"option_key": "D", "hint": "While diffraction and interference can produce colours (as in thin films), rainbow formation is primarily due to refraction, internal reflection and dispersion in water droplets.", "misconception": "Confusing rainbow formation with thin-film interference"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A ray of light is incident on an equilateral glass prism (n = 1.5) placed on a horizontal surface. For the ray to undergo total internal reflection at the second face, the minimum angle of incidence at the first face must satisfy:", "explanation": "For TIR at the second face, the angle of refraction r₂ at that face must be at least equal to the critical angle C, where sin C = 1/n = 1/1.5 = 2/3. For an equilateral prism, A = 60° and r₁ + r₂ = A. For r₂ = C, r₁ = 60° − C. Using Snell''s law at the first face: sin i = n sin r₁ = 1.5 × sin(60° − C). Since sin C = 2/3, we get C ≈ 41.8°, so r₁ = 18.2°. Then sin i = 1.5 × sin 18.2° ≈ 1.5 × 0.312 ≈ 0.468, giving i ≈ 27.9° ≈ 28°.", "correct_answer": "A", "concept_tags": ["total-internal-reflection", "prism", "critical-angle", "snell-law"], "payload": {"question_id": "cuet-phy-ray-prism-11", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "analyze", "options": [{"key": "A", "text": "The angle of incidence must be at least approximately 28°", "is_correct": true}, {"key": "B", "text": "The angle of incidence must be at least 60°", "is_correct": false}, {"key": "C", "text": "Total internal reflection is not possible in this prism", "is_correct": false}, {"key": "D", "text": "The angle of incidence must be at least 45°", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "60° is the prism angle itself. The minimum angle of incidence for TIR at the second face is obtained by setting r₂ = C and computing i from Snell''s law.", "misconception": null}, {"option_key": "C", "hint": "TIR is possible at the second face of this prism if the angle of incidence at the first face is large enough to make r₂ ≥ C.", "misconception": "Incorrectly assuming TIR cannot occur in a prism"}, {"option_key": "D", "hint": "45° would correspond to a different prism geometry or refractive index. The calculation with n = 1.5 and A = 60° gives approximately 28°.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two thin prisms of angles 5° and 3° are made of materials with refractive indices 1.5 and 1.7 respectively. They are combined to produce dispersion without deviation. The ratio of their angular dispersions for the prism combination that achieves this is:", "explanation": "For no net deviation: (n₁ − 1)A₁ = (n₂ − 1)A₂, i.e., 0.5 × 5 = 0.7 × 3, which gives 2.5 = 2.1. Since these aren''t exactly equal, one prism must be inverted and the condition requires adjustable angles. However, in the standard NEET approach, the angular dispersion ratio equals the ratio of (n_v − n_r)A for each prism. For deviation without dispersion (or vice versa), the angular dispersions are in the ratio of the deviations: δ₁/δ₂ = (n₁ − 1)A₁ / (n₂ − 1)A₂ = 2.5/2.1 = 25:21.", "correct_answer": "D", "concept_tags": ["combination-of-prisms", "dispersion-without-deviation", "angular-dispersion"], "payload": {"question_id": "cuet-phy-ray-prism-12", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "analyze", "options": [{"key": "A", "text": "5 : 3", "is_correct": false}, {"key": "B", "text": "3 : 5", "is_correct": false}, {"key": "C", "text": "21 : 25", "is_correct": false}, {"key": "D", "text": "25 : 21", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "5:3 is just the ratio of prism angles and does not account for the different refractive indices of the materials.", "misconception": "Ignoring the role of refractive index in computing deviations"}, {"option_key": "B", "hint": "3:5 is the inverse of the prism angle ratio and has no physical basis for this problem.", "misconception": null}, {"option_key": "C", "hint": "21:25 is the inverse of the correct ratio. The first prism (larger δ) has the greater angular dispersion.", "misconception": "Inverting the ratio of angular dispersions"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Diamonds sparkle brilliantly due to total internal reflection.\nReason (R): Diamond has a very high refractive index (n ≈ 2.42) resulting in a small critical angle of about 24.4°.", "explanation": "Both the assertion and reason are correct, and the reason correctly explains the assertion. Diamond''s very high refractive index gives it a very small critical angle (sin C = 1/2.42, C ≈ 24.4°). This means light entering the diamond undergoes TIR at most internal surfaces, bouncing multiple times before emerging, which produces the brilliant sparkle.", "correct_answer": "A", "concept_tags": ["diamond", "total-internal-reflection", "critical-angle", "refractive-index"], "payload": {"question_id": "cuet-phy-ray-prism-13", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The small critical angle (from high n) is precisely why TIR occurs so readily inside diamond, directly explaining the sparkle.", "misconception": "Failing to connect high n and small critical angle to multiple TIR events"}, {"option_key": "C", "hint": "The reason is factually correct — diamond does have n ≈ 2.42 and a critical angle of about 24.4°.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct; diamonds do sparkle due to multiple total internal reflections.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): At minimum deviation through a prism, the refracted ray inside the prism travels parallel to the base of the prism.\nReason (R): At minimum deviation, the angle of incidence at the first face equals the angle of emergence at the second face.", "explanation": "Both A and R are correct. At minimum deviation, i = e and r₁ = r₂ = A/2, which makes the ray inside the prism symmetric with respect to the prism. For a prism with its base horizontal, this symmetric path means the internal ray is parallel to the base. The reason (i = e) is the correct explanation because this symmetry condition leads to the parallel path inside.", "correct_answer": "A", "concept_tags": ["minimum-deviation", "prism-symmetry", "angle-of-incidence", "angle-of-emergence"], "payload": {"question_id": "cuet-phy-ray-prism-14", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The condition i = e directly leads to r₁ = r₂ = A/2, which makes the internal ray parallel to the base. So R is the correct explanation of A.", "misconception": null}, {"option_key": "C", "hint": "The reason is correct — at minimum deviation, it is well established that the angle of incidence equals the angle of emergence.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct — at minimum deviation, the refracted ray inside the prism does travel parallel to the base, which can be verified from the symmetry condition.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the optical phenomena in Column I with their correct descriptions in Column II:\n\nColumn I:\nA. Total internal reflection\nB. Dispersion\nC. Angular dispersion\nD. Dispersive power\n\nColumn II:\n1. Splitting of white light into component colours by a prism\n2. Ratio of angular dispersion to mean deviation\n3. Reflection of light when angle of incidence exceeds the critical angle in a denser medium\n4. Difference in deviations of violet and red light through a prism", "explanation": "Total internal reflection occurs when the angle of incidence in a denser medium exceeds the critical angle (A-3). Dispersion is the splitting of white light into its spectrum (B-1). Angular dispersion is the difference in deviations between violet and red light (C-4). Dispersive power is the ratio of angular dispersion to the mean deviation (D-2).", "correct_answer": "C", "concept_tags": ["total-internal-reflection", "dispersion", "angular-dispersion", "dispersive-power"], "payload": {"question_id": "cuet-phy-ray-prism-15", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "A-3, B-4, C-1, D-2", "is_correct": false}, {"key": "B", "text": "A-1, B-3, C-4, D-2", "is_correct": false}, {"key": "C", "text": "A-3, B-1, C-4, D-2", "is_correct": true}, {"key": "D", "text": "A-3, B-1, C-2, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and C. Dispersion is the splitting of light (B-1), not the deviation difference, and angular dispersion is the deviation difference (C-4), not the splitting.", "misconception": "Confusing dispersion with angular dispersion"}, {"option_key": "B", "hint": "This incorrectly assigns TIR to splitting of light (A-1) and dispersion to the critical angle condition (B-3).", "misconception": null}, {"option_key": "D", "hint": "This swaps C and D. Angular dispersion is δ_v − δ_r (C-4), while dispersive power is the ratio (δ_v − δ_r)/δ_y (D-2).", "misconception": "Interchanging angular dispersion and dispersive power"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the applications in Column I with the underlying principle in Column II:\n\nColumn I:\nA. Optical fibre communication\nB. Sparkling of diamond\nC. Formation of secondary rainbow\nD. Mirage in deserts\n\nColumn II:\n1. Two total internal reflections inside a water droplet\n2. Gradual refraction and TIR in air layers of varying density\n3. Repeated TIR at core-cladding interface\n4. Multiple TIR due to small critical angle", "explanation": "Optical fibres use repeated TIR at the core-cladding interface (A-3). Diamond sparkles due to multiple TIR because of its very small critical angle (B-4). A secondary rainbow involves two total internal reflections inside each water droplet (C-1). Mirages are formed by gradual refraction in hot air layers of varying density followed by TIR (D-2).", "correct_answer": "B", "concept_tags": ["optical-fibre", "diamond", "rainbow", "mirage", "total-internal-reflection"], "payload": {"question_id": "cuet-phy-ray-prism-16", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-3, B-1, C-4, D-2", "is_correct": false}, {"key": "B", "text": "A-3, B-4, C-1, D-2", "is_correct": true}, {"key": "C", "text": "A-4, B-3, C-1, D-2", "is_correct": false}, {"key": "D", "text": "A-3, B-4, C-2, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and C. Diamond sparkles due to its small critical angle (B-4), and the secondary rainbow involves two TIR events (C-1), not the reverse.", "misconception": null}, {"option_key": "C", "hint": "Optical fibres use repeated TIR at the core-cladding interface (A-3), not multiple TIR due to small critical angle (A-4).", "misconception": "Confusing optical fibre TIR mechanism with diamond''s TIR mechanism"}, {"option_key": "D", "hint": "This swaps C and D. The secondary rainbow involves two TIR events in a droplet (C-1), while mirages involve varying air density (D-2).", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The critical angle for a medium with refractive index 2 with respect to air is 30°.", "explanation": "The critical angle C is given by sin C = 1/n. For n = 2, sin C = 1/2 = 0.5, so C = sin⁻¹(0.5) = 30°. This statement is true.", "correct_answer": "A", "concept_tags": ["critical-angle", "refractive-index", "total-internal-reflection"], "payload": {"question_id": "cuet-phy-ray-prism-17", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The calculation sin C = 1/n = 1/2 gives C = 30°, confirming the statement is true.", "misconception": "Incorrectly computing the critical angle"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The deviation produced by a prism increases continuously as the angle of incidence increases from 0° to 90°.", "explanation": "This statement is false. As the angle of incidence increases from its minimum value, the deviation first decreases, reaches a minimum value (minimum deviation), and then increases again. The deviation-vs-incidence curve is U-shaped, not monotonically increasing.", "correct_answer": "B", "concept_tags": ["prism", "deviation", "angle-of-incidence", "minimum-deviation"], "payload": {"question_id": "cuet-phy-ray-prism-18", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The deviation first decreases to a minimum value and then increases. It does not increase continuously.", "misconception": "Assuming deviation increases monotonically with angle of incidence"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The angular dispersion produced by a thin prism of angle A for violet and red light is given by _____, where n_v and n_r are the refractive indices for violet and red light respectively.", "explanation": "For a thin prism, the deviation for any colour is δ = (n − 1)A. The angular dispersion is the difference in deviations of violet and red: δ_v − δ_r = (n_v − 1)A − (n_r − 1)A = (n_v − n_r)A. This formula shows angular dispersion depends on both the material (n_v − n_r) and the prism angle A.", "correct_answer": "C", "concept_tags": ["angular-dispersion", "thin-prism", "violet-red-deviation"], "payload": {"question_id": "cuet-phy-ray-prism-19", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "(n_v + n_r)A", "is_correct": false}, {"key": "B", "text": "(n_v − n_r)/A", "is_correct": false}, {"key": "C", "text": "(n_v − n_r)A", "is_correct": true}, {"key": "D", "text": "(n_v × n_r)A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Adding refractive indices (n_v + n_r) has no physical meaning in the context of angular dispersion, which is the difference in deviations.", "misconception": null}, {"option_key": "B", "hint": "Angular dispersion is proportional to A, not inversely proportional. Dividing by A gives the dispersive power (after normalisation), not angular dispersion.", "misconception": "Confusing angular dispersion formula with dispersive power"}, {"option_key": "D", "hint": "The product n_v × n_r has no relevance to angular dispersion. The correct expression involves the difference (n_v − n_r).", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A scuba diver is at the bottom of a swimming pool of depth 4 m. The refractive index of water is 4/3. The diver shines a torch upward. The light that exits the water surface forms a bright circle on the surface.\n\nWhat is the radius of this bright circle?", "explanation": "Light exits the water surface only if the angle of incidence is less than the critical angle C. The critical angle is given by sin C = 1/n = 3/4. The radius r of the bright circle is related to the depth h by r = h × tan C. Since sin C = 3/4, cos C = √(1 − 9/16) = √(7/16) = √7/4. So tan C = sin C/cos C = (3/4)/(√7/4) = 3/√7. Therefore r = 4 × 3/√7 = 12/√7 ≈ 4.53 m ≈ 4.5 m.", "correct_answer": "B", "concept_tags": ["critical-angle", "total-internal-reflection", "snell-law", "bright-circle"], "payload": {"question_id": "cuet-phy-ray-prism-20", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "3 m", "is_correct": false}, {"key": "B", "text": "12/√7 m", "is_correct": true}, {"key": "C", "text": "4 m", "is_correct": false}, {"key": "D", "text": "16/3 m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3 m would result from r = h × sin C = 4 × 3/4 = 3, but the correct formula uses tan C, not sin C.", "misconception": "Using sin C instead of tan C to find the radius"}, {"option_key": "C", "hint": "r = 4 m would imply tan C = 1 or C = 45°, but the critical angle for water (n = 4/3) is not 45°.", "misconception": null}, {"option_key": "D", "hint": "16/3 results from an incorrect formula. The correct approach gives r = h × tan C = 12/√7 m.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b14');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A ray of light is incident on a plane mirror at an angle of 30° with the mirror surface. What is the angle of reflection?", "explanation": "The angle of incidence is measured from the normal, not the surface. If the ray makes 30° with the mirror surface, the angle of incidence is 90° − 30° = 60°. By the law of reflection, the angle of reflection equals the angle of incidence, so it is 60°.", "correct_answer": "C", "concept_tags": ["law-of-reflection", "angle-of-incidence", "plane-mirror"], "payload": {"question_id": "cuet-phy-ray-reflection-01", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "remember", "options": [{"key": "A", "text": "30°", "is_correct": false}, {"key": "B", "text": "45°", "is_correct": false}, {"key": "C", "text": "60°", "is_correct": true}, {"key": "D", "text": "90°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "30° is the angle the ray makes with the mirror surface, not with the normal. The angle of reflection is measured from the normal.", "misconception": "Confusing angle with surface and angle with normal"}, {"option_key": "B", "hint": "45° would be correct only if the ray made 45° with the surface, which is not the case here.", "misconception": null}, {"option_key": "D", "hint": "90° would mean the reflected ray is along the normal, which only happens for normal incidence.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The image formed by a plane mirror is:", "explanation": "A plane mirror always forms a virtual, erect image that is laterally inverted and of the same size as the object. The image is located as far behind the mirror as the object is in front of it.", "correct_answer": "B", "concept_tags": ["plane-mirror", "virtual-image", "image-characteristics"], "payload": {"question_id": "cuet-phy-ray-reflection-02", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "remember", "options": [{"key": "A", "text": "Real, erect and of same size", "is_correct": false}, {"key": "B", "text": "Virtual, erect and of same size", "is_correct": true}, {"key": "C", "text": "Virtual, inverted and magnified", "is_correct": false}, {"key": "D", "text": "Real, inverted and of same size", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A plane mirror cannot form a real image because the reflected rays diverge and only appear to meet behind the mirror.", "misconception": "Confusing virtual and real images in plane mirrors"}, {"option_key": "C", "hint": "The image in a plane mirror is erect (not inverted top-to-bottom) and of the same size, not magnified.", "misconception": "Confusing lateral inversion with top-bottom inversion"}, {"option_key": "D", "hint": "Plane mirrors do not form real images; they always produce virtual images that cannot be captured on a screen.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The focal length of a concave mirror is 15 cm. What is its radius of curvature?", "explanation": "For a spherical mirror, the radius of curvature R is related to the focal length f by the relation R = 2f. Therefore, R = 2 × 15 = 30 cm.", "correct_answer": "A", "concept_tags": ["concave-mirror", "focal-length", "radius-of-curvature"], "payload": {"question_id": "cuet-phy-ray-reflection-03", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "remember", "options": [{"key": "A", "text": "30 cm", "is_correct": true}, {"key": "B", "text": "15 cm", "is_correct": false}, {"key": "C", "text": "7.5 cm", "is_correct": false}, {"key": "D", "text": "45 cm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "15 cm is the focal length itself, not the radius of curvature. R = 2f, not R = f.", "misconception": "Confusing focal length with radius of curvature"}, {"option_key": "C", "hint": "7.5 cm would result from dividing f by 2 instead of multiplying. The correct relation is R = 2f.", "misconception": "Inverting the R-f relationship"}, {"option_key": "D", "hint": "45 cm would result from R = 3f, which is not the correct relationship for spherical mirrors.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "When light travels from a denser medium to a rarer medium, it bends:", "explanation": "According to Snell''s law (n₁ sin θ₁ = n₂ sin θ₂), when light goes from a denser to a rarer medium (n₁ > n₂), the angle of refraction θ₂ is greater than the angle of incidence θ₁. Thus the refracted ray bends away from the normal.", "correct_answer": "D", "concept_tags": ["refraction", "snell-law", "denser-rarer-medium"], "payload": {"question_id": "cuet-phy-ray-reflection-04", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "remember", "options": [{"key": "A", "text": "Towards the normal", "is_correct": false}, {"key": "B", "text": "Along the normal", "is_correct": false}, {"key": "C", "text": "Parallel to the surface", "is_correct": false}, {"key": "D", "text": "Away from the normal", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Light bends towards the normal when going from a rarer to a denser medium, not the other way around.", "misconception": "Reversing the direction of bending in refraction"}, {"option_key": "B", "hint": "Light travels along the normal only when the angle of incidence is 0° (normal incidence), regardless of media.", "misconception": null}, {"option_key": "C", "hint": "Light becomes parallel to the surface only at the critical angle during total internal reflection, not in general refraction.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An object is placed at 20 cm in front of a concave mirror of focal length 10 cm. The magnification produced is:", "explanation": "Using the mirror formula 1/v + 1/u = 1/f with u = −20 cm and f = −10 cm: 1/v = 1/(−10) − 1/(−20) = −1/10 + 1/20 = −1/20, so v = −20 cm. Magnification m = −v/u = −(−20)/(−20) = −1. The image is real, inverted and of same size.", "correct_answer": "B", "concept_tags": ["concave-mirror", "mirror-formula", "magnification"], "payload": {"question_id": "cuet-phy-ray-reflection-05", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "apply", "options": [{"key": "A", "text": "+1", "is_correct": false}, {"key": "B", "text": "−1", "is_correct": true}, {"key": "C", "text": "−2", "is_correct": false}, {"key": "D", "text": "+2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "+1 magnification means a virtual, erect image of same size, which occurs for a plane mirror, not for an object at 2f of a concave mirror.", "misconception": "Ignoring the sign convention for magnification in mirrors"}, {"option_key": "C", "hint": "Magnification of −2 would occur when the object is placed between f and 2f (e.g., at 15 cm for f = 10 cm), not at 2f.", "misconception": null}, {"option_key": "D", "hint": "+2 would imply a virtual, erect, magnified image, which occurs when the object is between the pole and focus.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A convex mirror is used as a rear-view mirror in vehicles primarily because it:", "explanation": "A convex mirror always forms a virtual, erect and diminished image for all positions of the object. This gives a wider field of view compared to a plane mirror, making it ideal for rear-view mirrors in vehicles where observing a large area behind is essential for safety.", "correct_answer": "C", "concept_tags": ["convex-mirror", "field-of-view", "rear-view-mirror", "applications"], "payload": {"question_id": "cuet-phy-ray-reflection-06", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "understand", "options": [{"key": "A", "text": "Forms a real and magnified image", "is_correct": false}, {"key": "B", "text": "Forms a virtual and magnified image", "is_correct": false}, {"key": "C", "text": "Forms an erect, diminished image and provides a wider field of view", "is_correct": true}, {"key": "D", "text": "Forms an image of the same size as the object", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Convex mirrors never form real images; they always form virtual images since reflected rays diverge.", "misconception": "Confusing convex mirror properties with concave mirror properties"}, {"option_key": "B", "hint": "Convex mirrors always form diminished images, not magnified ones. Only concave mirrors can produce magnified images.", "misconception": null}, {"option_key": "D", "hint": "A convex mirror always produces a diminished image (smaller than the object), never the same size.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The refractive index of glass with respect to air is 1.5. What is the speed of light in glass if the speed of light in vacuum is 3 × 10⁸ m/s?", "explanation": "The refractive index n of a medium is defined as n = c/v, where c is the speed of light in vacuum and v is the speed in the medium. Therefore, v = c/n = (3 × 10⁸)/1.5 = 2 × 10⁸ m/s.", "correct_answer": "A", "concept_tags": ["refractive-index", "speed-of-light", "optical-density"], "payload": {"question_id": "cuet-phy-ray-reflection-07", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "apply", "options": [{"key": "A", "text": "2 × 10⁸ m/s", "is_correct": true}, {"key": "B", "text": "4.5 × 10⁸ m/s", "is_correct": false}, {"key": "C", "text": "1.5 × 10⁸ m/s", "is_correct": false}, {"key": "D", "text": "3 × 10⁸ m/s", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "4.5 × 10⁸ m/s = c × n, which is greater than c. No material medium can allow light to travel faster than c.", "misconception": "Multiplying c by n instead of dividing"}, {"option_key": "C", "hint": "1.5 × 10⁸ m/s would correspond to n = 2, not 1.5. Check the calculation v = c/n.", "misconception": null}, {"option_key": "D", "hint": "3 × 10⁸ m/s is the speed in vacuum. Light slows down in any material medium with n > 1.", "misconception": "Assuming speed of light is the same in all media"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An object is placed at 30 cm from a convex mirror of focal length 20 cm. The position of the image from the mirror is:", "explanation": "For a convex mirror, f = +20 cm and u = −30 cm. Using mirror formula: 1/v = 1/f − 1/u = 1/20 − 1/(−30) = 1/20 + 1/30 = (3 + 2)/60 = 5/60 = 1/12. So v = +12 cm. The positive sign confirms the image is behind the mirror (virtual).", "correct_answer": "D", "concept_tags": ["convex-mirror", "mirror-formula", "image-distance"], "payload": {"question_id": "cuet-phy-ray-reflection-08", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "apply", "options": [{"key": "A", "text": "60 cm behind the mirror", "is_correct": false}, {"key": "B", "text": "20 cm in front of the mirror", "is_correct": false}, {"key": "C", "text": "15 cm behind the mirror", "is_correct": false}, {"key": "D", "text": "12 cm behind the mirror", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "60 cm is far too large; for a convex mirror the image always lies between the pole and the focus, i.e., within 20 cm behind the mirror.", "misconception": null}, {"option_key": "B", "hint": "A convex mirror always forms a virtual image behind the mirror, never a real image in front.", "misconception": "Confusing convex mirror with concave mirror image positions"}, {"option_key": "C", "hint": "15 cm results from an arithmetic error. Carefully compute 1/20 + 1/30 = 5/60 = 1/12, giving v = 12 cm.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A ray of light passes from glass (n = 1.5) into water (n = 1.33). If the angle of incidence is 30°, the angle of refraction is approximately:", "explanation": "Applying Snell''s law: n₁ sin θ₁ = n₂ sin θ₂, so 1.5 × sin 30° = 1.33 × sin θ₂. This gives sin θ₂ = (1.5 × 0.5)/1.33 = 0.75/1.33 = 0.564. Therefore θ₂ = sin⁻¹(0.564) ≈ 34.3° ≈ 34°.", "correct_answer": "B", "concept_tags": ["snell-law", "refraction", "refractive-index"], "payload": {"question_id": "cuet-phy-ray-reflection-09", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "apply", "options": [{"key": "A", "text": "26°", "is_correct": false}, {"key": "B", "text": "34°", "is_correct": true}, {"key": "C", "text": "45°", "is_correct": false}, {"key": "D", "text": "30°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "26° would correspond to bending towards the normal, but light going from a denser (glass) to a less dense medium (water) bends away from the normal.", "misconception": "Reversing the direction of bending at the interface"}, {"option_key": "C", "hint": "45° is too large; sin 45° = 0.707, but the calculation gives sin θ₂ ≈ 0.564.", "misconception": null}, {"option_key": "D", "hint": "The refracted angle equals the incident angle only if both media have the same refractive index, which is not the case here.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A biconvex lens has radii of curvature R₁ = 20 cm and R₂ = 30 cm and refractive index 1.5. Its focal length using the lens maker''s equation is:", "explanation": "Using the lens maker''s equation: 1/f = (n − 1)[1/R₁ − 1/R₂] = (1.5 − 1)[1/20 − 1/(−30)] = 0.5 × [1/20 + 1/30] = 0.5 × (3 + 2)/60 = 0.5 × 5/60 = 0.5/12 = 1/24. Therefore f = 24 cm.", "correct_answer": "C", "concept_tags": ["lens-maker-equation", "biconvex-lens", "focal-length"], "payload": {"question_id": "cuet-phy-ray-reflection-10", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "apply", "options": [{"key": "A", "text": "12 cm", "is_correct": false}, {"key": "B", "text": "20 cm", "is_correct": false}, {"key": "C", "text": "24 cm", "is_correct": true}, {"key": "D", "text": "30 cm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "12 cm results from forgetting the (n − 1) factor and using 1/f = 1/R₁ + 1/R₂ directly.", "misconception": "Omitting the (n − 1) factor in the lens maker''s equation"}, {"option_key": "B", "hint": "20 cm is just the value of R₁; the focal length depends on both radii and the refractive index.", "misconception": null}, {"option_key": "D", "hint": "30 cm is just the value of R₂; the correct calculation involves both radii in the lens maker''s formula.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A concave mirror forms a real image of an object placed beyond its centre of curvature. If the object is moved towards the focus of the mirror, the image:", "explanation": "When the object is beyond C, the real image lies between F and C. As the object moves from beyond C towards F, the image moves from between F and C towards infinity. Thus the image moves farther from the mirror and its size increases (magnification increases in magnitude).", "correct_answer": "D", "concept_tags": ["concave-mirror", "image-movement", "magnification", "object-at-focus"], "payload": {"question_id": "cuet-phy-ray-reflection-11", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "analyze", "options": [{"key": "A", "text": "Moves towards the mirror and becomes smaller", "is_correct": false}, {"key": "B", "text": "Remains at the same position with the same size", "is_correct": false}, {"key": "C", "text": "Moves towards the mirror and becomes larger", "is_correct": false}, {"key": "D", "text": "Moves away from the mirror and becomes larger", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This is the reverse of what happens. As the object approaches the focus, the image recedes and enlarges, not the opposite.", "misconception": "Reversing the direction of image motion for concave mirrors"}, {"option_key": "B", "hint": "The image position and size remain unchanged only if the object position does not change. Moving the object changes the image.", "misconception": null}, {"option_key": "C", "hint": "The image does become larger, but it moves away from the mirror, not towards it, as the object approaches the focus.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A thin convex lens of focal length 20 cm is placed in contact with a thin concave lens of focal length 30 cm. The combination acts as a:", "explanation": "For lenses in contact, the equivalent focal length is given by 1/f = 1/f₁ + 1/f₂ = 1/20 + 1/(−30) = 3/60 − 2/60 = 1/60. So f = +60 cm. Since the focal length is positive, the combination acts as a converging (convex) lens of focal length 60 cm.", "correct_answer": "A", "concept_tags": ["combination-of-lenses", "equivalent-focal-length", "convex-lens", "concave-lens"], "payload": {"question_id": "cuet-phy-ray-reflection-12", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "analyze", "options": [{"key": "A", "text": "Converging lens of focal length 60 cm", "is_correct": true}, {"key": "B", "text": "Diverging lens of focal length 60 cm", "is_correct": false}, {"key": "C", "text": "Converging lens of focal length 10 cm", "is_correct": false}, {"key": "D", "text": "Diverging lens of focal length 10 cm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The calculated focal length is +60 cm (positive), which indicates a converging lens, not a diverging one.", "misconception": "Confusing the sign of the equivalent focal length"}, {"option_key": "C", "hint": "10 cm results from incorrectly subtracting: 1/20 − 1/30 ≠ 1/10. The correct calculation gives 1/60.", "misconception": "Arithmetic error in combining lens powers"}, {"option_key": "D", "hint": "Neither the focal length (60 cm, not 10 cm) nor the nature (converging, not diverging) matches this option.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): A concave mirror can form both real and virtual images.\nReason (R): When an object is placed between the pole and the focus of a concave mirror, the reflected rays diverge and appear to come from behind the mirror.", "explanation": "Both the assertion and reason are correct. A concave mirror forms real images when the object is beyond the focus and virtual images when the object is between the pole and focus. The reason correctly explains why a virtual image forms in the latter case — the reflected rays diverge and appear to originate from behind the mirror.", "correct_answer": "A", "concept_tags": ["concave-mirror", "real-virtual-image", "image-formation"], "payload": {"question_id": "cuet-phy-ray-reflection-13", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains how the virtual image forms, which is one part of the assertion. Hence R is the correct explanation of A.", "misconception": "Failing to see the causal link between R and A"}, {"option_key": "C", "hint": "The reason is physically accurate — reflected rays from an object between P and F do diverge, forming a virtual image behind the mirror.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct; concave mirrors can indeed form both real and virtual images depending on object position.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The refractive index of a medium depends on the wavelength of light used.\nReason (R): The speed of light in a medium is the same for all wavelengths.", "explanation": "The assertion is correct because the refractive index n = c/v, and the speed v of light in a dispersive medium varies with wavelength (this is the cause of dispersion). The reason is incorrect because the speed of light in a material medium does depend on wavelength — violet light travels slower than red light in glass, for example.", "correct_answer": "C", "concept_tags": ["refractive-index", "dispersion", "wavelength-dependence", "speed-of-light"], "payload": {"question_id": "cuet-phy-ray-reflection-14", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": true}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The reason is factually incorrect — the speed of light in a material medium does vary with wavelength, causing dispersion.", "misconception": null}, {"option_key": "B", "hint": "Since the reason is incorrect (speed does depend on wavelength in a medium), this option cannot be chosen.", "misconception": "Believing speed of light is wavelength-independent in all media"}, {"option_key": "D", "hint": "The assertion is correct; refractive index is wavelength-dependent (e.g., Cauchy''s equation describes this dependence).", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following mirror types with the nature of the image formed:\n\nColumn I:\nA. Concave mirror (object at infinity)\nB. Convex mirror (any object position)\nC. Concave mirror (object between P and F)\nD. Plane mirror\n\nColumn II:\n1. Virtual, erect, same size\n2. Real, inverted, highly diminished (at focus)\n3. Virtual, erect, diminished\n4. Virtual, erect, magnified", "explanation": "A concave mirror forms a real, inverted, point-sized image at the focus when the object is at infinity (A-2). A convex mirror always forms a virtual, erect, diminished image (B-3). A concave mirror with the object between P and F gives a virtual, erect, magnified image (C-4). A plane mirror forms a virtual, erect, same-sized image (D-1).", "correct_answer": "B", "concept_tags": ["mirror-types", "image-characteristics", "concave-mirror", "convex-mirror", "plane-mirror"], "payload": {"question_id": "cuet-phy-ray-reflection-15", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "understand", "options": [{"key": "A", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-3, C-4, D-1", "is_correct": true}, {"key": "C", "text": "A-4, B-3, C-2, D-1", "is_correct": false}, {"key": "D", "text": "A-1, B-2, C-3, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This incorrectly assigns a virtual magnified image to a convex mirror (B-4). Convex mirrors always form diminished images.", "misconception": "Confusing image properties of convex and concave mirrors"}, {"option_key": "C", "hint": "A-4 is wrong; a concave mirror with the object at infinity forms a real diminished image at the focus, not a virtual magnified one.", "misconception": null}, {"option_key": "D", "hint": "This option assigns completely incorrect image types to all mirrors and has no physical basis.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the optical phenomena in Column I with their correct physical basis in Column II:\n\nColumn I:\nA. Twinkling of stars\nB. Apparent depth of a swimming pool is less than actual depth\nC. Lateral displacement of a ray through a glass slab\nD. Bending of light around sharp edges\n\nColumn II:\n1. Refraction at parallel surfaces\n2. Atmospheric refraction due to varying refractive index\n3. Refraction at a plane surface\n4. Diffraction", "explanation": "Twinkling of stars is caused by atmospheric refraction due to turbulent layers with varying refractive index (A-2). The apparent decrease in depth of a pool is due to refraction at the plane water surface (B-3). Lateral displacement through a glass slab occurs because of refraction at two parallel surfaces (C-1). Bending of light around sharp edges is diffraction (D-4).", "correct_answer": "D", "concept_tags": ["atmospheric-refraction", "apparent-depth", "lateral-displacement", "diffraction"], "payload": {"question_id": "cuet-phy-ray-reflection-16", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-3, B-2, C-1, D-4", "is_correct": false}, {"key": "C", "text": "A-2, B-3, C-4, D-1", "is_correct": false}, {"key": "D", "text": "A-2, B-3, C-1, D-4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and C. Apparent depth is due to refraction at a single plane surface (B-3), while lateral displacement involves two parallel surfaces (C-1).", "misconception": null}, {"option_key": "B", "hint": "Twinkling of stars (A) is due to atmospheric refraction (2), not refraction at a single plane surface (3).", "misconception": "Confusing atmospheric refraction with simple refraction"}, {"option_key": "C", "hint": "This incorrectly assigns diffraction (4) to lateral displacement and refraction at parallel surfaces (1) to bending around edges.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The angle of incidence is equal to the angle of reflection for all reflecting surfaces.", "explanation": "This is a statement of the law of reflection, which holds true for all reflecting surfaces — whether plane, concave, convex, or irregular. The angles are measured with respect to the normal at the point of incidence.", "correct_answer": "A", "concept_tags": ["law-of-reflection", "angle-of-incidence", "angle-of-reflection"], "payload": {"question_id": "cuet-phy-ray-reflection-17", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The law of reflection (angle of incidence = angle of reflection) is universally valid for all reflecting surfaces.", "misconception": "Thinking the law of reflection applies only to plane mirrors"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A convex mirror can form a real image of a real object.", "explanation": "This statement is false. A convex mirror always forms a virtual, erect and diminished image for any position of a real object. The reflected rays always diverge and only appear to meet behind the mirror, so the image is always virtual.", "correct_answer": "B", "concept_tags": ["convex-mirror", "virtual-image", "image-formation"], "payload": {"question_id": "cuet-phy-ray-reflection-18", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A convex mirror cannot form a real image of a real object. The diverging nature of the mirror ensures all images are virtual.", "misconception": "Confusing convex mirror with concave mirror capabilities"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The power of a convex lens of focal length 25 cm is _____ dioptre.", "explanation": "The power of a lens is given by P = 1/f, where f is in metres. Converting 25 cm to metres: f = 0.25 m. Therefore P = 1/0.25 = +4 D. The positive sign indicates a converging lens.", "correct_answer": "D", "concept_tags": ["power-of-lens", "focal-length", "dioptre"], "payload": {"question_id": "cuet-phy-ray-reflection-19", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "apply", "options": [{"key": "A", "text": "+0.25", "is_correct": false}, {"key": "B", "text": "+25", "is_correct": false}, {"key": "C", "text": "−4", "is_correct": false}, {"key": "D", "text": "+4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "+0.25 would be the focal length in metres, not the power. Power = 1/f, not f itself.", "misconception": "Confusing focal length (in metres) with power"}, {"option_key": "B", "hint": "+25 results from using f in cm directly in P = 1/f. The focal length must be converted to metres first.", "misconception": "Forgetting to convert cm to m when calculating power"}, {"option_key": "C", "hint": "−4 D would be the power of a concave (diverging) lens. A convex lens has positive power.", "misconception": "Using wrong sign for convex lens power"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A student places a 5 cm tall candle at a distance of 25 cm from a concave mirror of focal length 15 cm. She observes a clear image on a screen placed on the same side as the candle.\n\nWhat is the height of the image formed on the screen?", "explanation": "Using mirror formula with u = −25 cm and f = −15 cm: 1/v = 1/f − 1/u = 1/(−15) − 1/(−25) = −1/15 + 1/25 = (−5 + 3)/75 = −2/75. So v = −37.5 cm. Magnification m = −v/u = −(−37.5)/(−25) = −1.5. Image height = m × object height = −1.5 × 5 = −7.5 cm. The negative sign indicates the image is inverted. The magnitude of the image height is 7.5 cm.", "correct_answer": "C", "concept_tags": ["concave-mirror", "mirror-formula", "magnification", "image-height"], "payload": {"question_id": "cuet-phy-ray-reflection-20", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "apply", "options": [{"key": "A", "text": "5 cm, erect", "is_correct": false}, {"key": "B", "text": "3.33 cm, inverted", "is_correct": false}, {"key": "C", "text": "7.5 cm, inverted", "is_correct": true}, {"key": "D", "text": "10 cm, inverted", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "An image of the same height (5 cm) would occur only when the object is at the centre of curvature (2f = 30 cm), not at 25 cm.", "misconception": "Assuming the image size equals object size for all positions"}, {"option_key": "B", "hint": "3.33 cm results from an error in computing v. Carefully re-evaluate 1/(−15) − 1/(−25) to get v = −37.5 cm.", "misconception": null}, {"option_key": "D", "hint": "10 cm would require a magnification of 2, which does not match the object distance of 25 cm and focal length of 15 cm.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b14');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In single slit diffraction, the condition for the first minimum is:", "explanation": "In single slit Fraunhofer diffraction, destructive interference (minima) occurs when the path difference between the extreme rays from the slit equals an integral multiple of the wavelength. The condition for the nth minimum is a sin θ = nλ. For the first minimum, n = 1, so a sin θ = λ.", "correct_answer": "A", "concept_tags": ["single-slit-diffraction", "minima-condition", "path-difference"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-01", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "a sin θ = λ", "is_correct": true}, {"key": "B", "text": "a sin θ = λ/2", "is_correct": false}, {"key": "C", "text": "a sin θ = 2λ", "is_correct": false}, {"key": "D", "text": "a sin θ = 3λ/2", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "a sin θ = λ/2 does not correspond to either a maximum or minimum in single slit diffraction. The minima occur at whole multiples of λ.", "misconception": "Confusing single slit diffraction minima with double slit interference conditions"}, {"option_key": "C", "hint": "a sin θ = 2λ gives the second minimum (n = 2), not the first.", "misconception": "Using wrong order number for the first minimum"}, {"option_key": "D", "hint": "a sin θ = 3λ/2 approximately corresponds to a secondary maximum, not the first minimum.", "misconception": "Confusing the condition for secondary maxima with minima"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The angular width of the central maximum in a single slit Fraunhofer diffraction pattern is:", "explanation": "In single slit Fraunhofer diffraction, the first minimum on either side occurs at sin θ = λ/a. For small angles, θ ≈ λ/a. Since the central maximum extends from the first minimum on one side to the first minimum on the other side, the total angular width of the central maximum is 2θ = 2λ/a.", "correct_answer": "B", "concept_tags": ["central-maximum", "angular-width", "single-slit-diffraction"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-02", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "λ/a", "is_correct": false}, {"key": "B", "text": "2λ/a", "is_correct": true}, {"key": "C", "text": "λ/2a", "is_correct": false}, {"key": "D", "text": "3λ/a", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "λ/a gives the angular half-width (from the centre to the first minimum on one side), not the full angular width.", "misconception": "Confusing half angular width with full angular width of central maximum"}, {"option_key": "C", "hint": "λ/2a is half the angular half-width and has no standard significance in the diffraction pattern.", "misconception": "Incorrectly halving the angular width formula"}, {"option_key": "D", "hint": "3λ/a does not correspond to the angular width of the central maximum. The central maximum spans only 2λ/a.", "misconception": "Using the wrong multiple of λ/a"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Rayleigh''s criterion, two point sources are just resolved when the central maximum of one falls on the:", "explanation": "Rayleigh''s criterion for the limit of resolution states that two point sources are just resolved when the central maximum of the diffraction pattern of one source falls on the first minimum of the diffraction pattern of the other. This provides a practical definition of the minimum angular separation for resolution.", "correct_answer": "C", "concept_tags": ["rayleigh-criterion", "resolving-power", "limit-of-resolution"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-03", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "Central maximum of the other", "is_correct": false}, {"key": "B", "text": "Second minimum of the other", "is_correct": false}, {"key": "C", "text": "First minimum of the other", "is_correct": true}, {"key": "D", "text": "First secondary maximum of the other", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "If the central maxima of both patterns coincide, the two sources would appear as one and would be completely unresolved.", "misconception": "Thinking coincident maxima means just resolved"}, {"option_key": "B", "hint": "If the central maximum falls on the second minimum, the sources are well resolved (over-resolved), not just resolved.", "misconception": "Confusing well-resolved with just-resolved condition"}, {"option_key": "D", "hint": "The first secondary maximum is farther than the first minimum. This would give an over-resolved condition, not just resolved.", "misconception": "Confusing the positions of secondary maxima and minima"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In Fraunhofer diffraction, the source of light and the screen are effectively at:", "explanation": "In Fraunhofer diffraction, both the source and the screen are effectively at infinite distance from the diffracting aperture. This is achieved in practice by using a collimating lens to produce parallel light from the source and a converging lens to focus the diffracted light onto the screen. In contrast, in Fresnel diffraction, either the source or the screen (or both) are at finite distances.", "correct_answer": "D", "concept_tags": ["fraunhofer-diffraction", "fresnel-diffraction", "parallel-rays"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-04", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "Finite distance from the slit", "is_correct": false}, {"key": "B", "text": "The focus of the lens", "is_correct": false}, {"key": "C", "text": "Very close to the slit", "is_correct": false}, {"key": "D", "text": "Infinite distance from the slit", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Finite distance from the slit describes Fresnel diffraction, not Fraunhofer diffraction.", "misconception": "Confusing Fresnel diffraction conditions with Fraunhofer diffraction"}, {"option_key": "B", "hint": "While lenses are used in the experimental setup, the condition is about the effective distance of the source and screen, which must be infinite.", "misconception": "Confusing the experimental setup with the defining condition"}, {"option_key": "C", "hint": "Placing the source very close to the slit would produce near-field (Fresnel) diffraction, not Fraunhofer diffraction.", "misconception": "Confusing near-field with far-field diffraction"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A single slit of width 0.1 mm is illuminated by a parallel beam of light of wavelength 6000 Å. The angular width of the central maximum on a screen is:", "explanation": "The angular width of the central maximum in single slit diffraction is 2θ = 2λ/a (for small angles). Given: a = 0.1 mm = 0.1 × 10⁻³ m = 10⁻⁴ m and λ = 6000 Å = 6 × 10⁻⁷ m. Angular width = 2λ/a = 2 × 6 × 10⁻⁷ / 10⁻⁴ = 12 × 10⁻³ rad = 1.2 × 10⁻² rad.", "correct_answer": "C", "concept_tags": ["angular-width", "central-maximum", "numerical-problem"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-05", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "6 × 10⁻³ rad", "is_correct": false}, {"key": "B", "text": "1.2 × 10⁻³ rad", "is_correct": false}, {"key": "C", "text": "1.2 × 10⁻² rad", "is_correct": true}, {"key": "D", "text": "6 × 10⁻² rad", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6 × 10⁻³ rad is the half angular width (λ/a), not the full angular width of the central maximum.", "misconception": "Forgetting to multiply by 2 for the full angular width"}, {"option_key": "B", "hint": "This is off by a factor of 10. Check your unit conversion of slit width carefully.", "misconception": "Error in converting mm to metres"}, {"option_key": "D", "hint": "This value is too large. Recheck the calculation: 2 × 6 × 10⁻⁷ / 10⁻⁴ = 1.2 × 10⁻², not 6 × 10⁻².", "misconception": "Arithmetic error in the calculation"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the width of the slit in a single slit diffraction experiment is doubled, the width of the central maximum:", "explanation": "The angular width of the central maximum is 2λ/a. If the slit width ''a'' is doubled, the angular width becomes 2λ/(2a) = λ/a, which is half the original angular width. Since the linear width on the screen is proportional to the angular width (linear width = 2λD/a, where D is the distance to the screen), the width of the central maximum is halved when the slit width is doubled.", "correct_answer": "B", "concept_tags": ["slit-width-effect", "central-maximum", "diffraction-pattern"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-06", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "Becomes doubled", "is_correct": false}, {"key": "B", "text": "Becomes halved", "is_correct": true}, {"key": "C", "text": "Remains unchanged", "is_correct": false}, {"key": "D", "text": "Becomes one-fourth", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The width of the central maximum is inversely proportional to the slit width. Doubling the slit width decreases, not increases, the central maximum width.", "misconception": "Thinking slit width and central maximum width are directly proportional"}, {"option_key": "C", "hint": "The angular width 2λ/a clearly depends on ''a''. Changing the slit width must change the pattern.", "misconception": "Ignoring the dependence of diffraction pattern on slit width"}, {"option_key": "D", "hint": "The width is inversely proportional to ''a'' (not to a²), so doubling ''a'' halves the width, not quarters it.", "misconception": "Confusing inverse proportionality with inverse square relationship"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The resolving power of a telescope can be increased by:", "explanation": "The minimum angular separation that a telescope can resolve is given by θ = 1.22λ/D, where D is the diameter of the objective lens (or mirror). Resolving power is the reciprocal of this: RP = D/(1.22λ). Therefore, increasing the diameter of the objective lens increases the resolving power. Using light of shorter wavelength also increases resolving power.", "correct_answer": "A", "concept_tags": ["resolving-power-telescope", "objective-diameter", "rayleigh-criterion"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-07", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "Increasing the diameter of the objective lens", "is_correct": true}, {"key": "B", "text": "Increasing the focal length of the objective lens", "is_correct": false}, {"key": "C", "text": "Increasing the focal length of the eyepiece", "is_correct": false}, {"key": "D", "text": "Increasing the wavelength of light used", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The resolving power formula θ = 1.22λ/D depends on the diameter, not the focal length. Focal length affects magnifying power, not resolving power.", "misconception": "Confusing resolving power with magnifying power of a telescope"}, {"option_key": "C", "hint": "The eyepiece focal length affects magnification, not the ability to resolve two closely spaced objects.", "misconception": "Mixing up the roles of eyepiece and objective in resolution"}, {"option_key": "D", "hint": "Since θ = 1.22λ/D, increasing λ increases the minimum resolvable angle, which means the resolving power decreases.", "misconception": "Thinking larger wavelength gives better resolution"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a single slit diffraction pattern, the intensity of the central maximum is I₀. The intensity at the first secondary maximum is approximately:", "explanation": "In single slit diffraction, the intensity distribution is I = I₀ [sin(β/2)/(β/2)]², where β = (2πa sinθ)/λ. The first secondary maximum occurs approximately at β/2 ≈ 3π/2. The intensity at this point is I = I₀ [sin(3π/2)/(3π/2)]² = I₀ [1/(3π/2)]² = I₀ × 4/(9π²) ≈ I₀/22. This is approximately 4.5% of the central maximum intensity.", "correct_answer": "D", "concept_tags": ["intensity-distribution", "secondary-maxima", "single-slit-diffraction"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-08", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "I₀/2", "is_correct": false}, {"key": "B", "text": "I₀/4", "is_correct": false}, {"key": "C", "text": "I₀/9", "is_correct": false}, {"key": "D", "text": "I₀/22 (approximately)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "I₀/2 would mean the secondary maxima are very bright. In reality, the secondary maxima are much fainter than the central maximum.", "misconception": "Underestimating how rapidly intensity falls off in diffraction"}, {"option_key": "B", "hint": "I₀/4 is still too high. The intensity at secondary maxima follows the [sin(x)/x]² function which drops off steeply.", "misconception": "Using incorrect formula for secondary maxima intensity"}, {"option_key": "C", "hint": "I₀/9 is close but incorrect. The exact value involves π² in the denominator: 4/(9π²) ≈ 1/22.", "misconception": "Forgetting the π² factor in the intensity formula"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The resolving power of a microscope is given by:", "explanation": "The resolving power of a microscope is the reciprocal of the minimum distance between two point objects that can be just resolved. Using Abbe''s theory, the minimum resolvable distance is d_min = λ/(2n sinθ), where n sinθ is the numerical aperture (NA) of the objective. Therefore, resolving power = 1/d_min = 2n sinθ/λ. Higher numerical aperture and shorter wavelength improve the resolving power.", "correct_answer": "C", "concept_tags": ["resolving-power-microscope", "numerical-aperture", "limit-of-resolution"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-09", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "D/(1.22λ)", "is_correct": false}, {"key": "B", "text": "λ/(2n sinθ)", "is_correct": false}, {"key": "C", "text": "2n sinθ/λ", "is_correct": true}, {"key": "D", "text": "1.22λ/D", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "D/(1.22λ) is the resolving power of a telescope, not a microscope. Telescope resolution depends on the objective diameter D.", "misconception": "Confusing telescope resolving power formula with microscope"}, {"option_key": "B", "hint": "λ/(2n sinθ) is the limit of resolution (minimum resolvable distance), not the resolving power itself. Resolving power is the reciprocal of this.", "misconception": "Confusing limit of resolution with resolving power"}, {"option_key": "D", "hint": "1.22λ/D is the limit of resolution of a telescope (minimum resolvable angle), not the resolving power of a microscope.", "misconception": "Mixing up telescope and microscope resolution formulae"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A diffraction grating has 5000 lines per cm. The angular separation between the first order maxima of two spectral lines of wavelengths 5890 Å and 5896 Å is approximately:", "explanation": "The grating equation is d sinθ = nλ. The grating spacing d = 1/5000 cm = 2 × 10⁻⁴ cm = 2 × 10⁻⁶ m. For first order (n = 1): sinθ₁ = λ₁/d = 5890 × 10⁻¹⁰ / (2 × 10⁻⁶) = 0.2945 and sinθ₂ = 5896 × 10⁻¹⁰ / (2 × 10⁻⁶) = 0.2948. The angular separation dθ ≈ (d(sinθ))/cosθ. Since Δ(sinθ) = 3 × 10⁻⁴ and cosθ ≈ cos(17.1°) ≈ 0.9554, we get dθ ≈ 3 × 10⁻⁴/0.9554 ≈ 3.14 × 10⁻⁴ rad ≈ 0.01°. So approximately 0.01°.", "correct_answer": "B", "concept_tags": ["diffraction-grating", "angular-separation", "spectral-lines"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-10", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "0.1°", "is_correct": false}, {"key": "B", "text": "0.01°", "is_correct": true}, {"key": "C", "text": "1°", "is_correct": false}, {"key": "D", "text": "0.001°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.1° is ten times too large. The wavelength difference is only 6 Å, which produces a very small angular separation in first order.", "misconception": "Error in order of magnitude calculation"}, {"option_key": "C", "hint": "1° is far too large for such a small wavelength difference of just 6 Å.", "misconception": "Gross overestimation of angular separation"}, {"option_key": "D", "hint": "0.001° is ten times too small. Recheck the calculation of sinθ difference and the conversion to degrees.", "misconception": "Error in unit conversion from radians to degrees"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A telescope has an objective lens of diameter 200 cm. The minimum angular separation between two stars that can just be resolved by this telescope, for light of wavelength 5500 Å, is approximately:", "explanation": "By Rayleigh''s criterion, the minimum angular separation θ = 1.22λ/D. Given: λ = 5500 Å = 5.5 × 10⁻⁷ m and D = 200 cm = 2 m. Therefore, θ = 1.22 × 5.5 × 10⁻⁷ / 2 = 1.22 × 2.75 × 10⁻⁷ = 3.355 × 10⁻⁷ rad ≈ 3.36 × 10⁻⁷ rad.", "correct_answer": "A", "concept_tags": ["rayleigh-criterion", "telescope-resolution", "numerical-problem"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-11", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "3.36 × 10⁻⁷ rad", "is_correct": true}, {"key": "B", "text": "6.72 × 10⁻⁷ rad", "is_correct": false}, {"key": "C", "text": "3.36 × 10⁻⁵ rad", "is_correct": false}, {"key": "D", "text": "1.68 × 10⁻⁷ rad", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "6.72 × 10⁻⁷ rad is double the correct answer. You may have used D = 1 m instead of D = 2 m.", "misconception": "Incorrect unit conversion of diameter from cm to m"}, {"option_key": "C", "hint": "This answer is 100 times too large. Check your unit conversion of the wavelength from angstrom to metres.", "misconception": "Error in converting angstroms to metres"}, {"option_key": "D", "hint": "1.68 × 10⁻⁷ is half the correct answer. You may have used D = 4 m or missed the factor 1.22.", "misconception": "Computational error with the 1.22 factor"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A diffraction grating has 6000 lines/cm. The maximum number of orders visible with light of wavelength 5000 Å is:", "explanation": "The grating equation is d sinθ = nλ. The maximum order occurs when sinθ = 1 (i.e., θ = 90°). The grating spacing d = 1/6000 cm = 1.667 × 10⁻⁴ cm = 1.667 × 10⁻⁶ m. Maximum order n_max = d/λ = 1.667 × 10⁻⁶ / (5 × 10⁻⁷) = 3.33. Since n must be an integer, the maximum order is n = 3. Counting both sides of the central maximum and the central maximum itself, the total number of orders visible is 2 × 3 + 1 = 7. However, when asking for the maximum order number, it is 3.", "correct_answer": "D", "concept_tags": ["diffraction-grating", "maximum-order", "grating-equation"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-12", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "5", "is_correct": false}, {"key": "B", "text": "4", "is_correct": false}, {"key": "C", "text": "2", "is_correct": false}, {"key": "D", "text": "3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "n_max = d/λ = 3.33, so n cannot exceed 3. A value of 5 would require sinθ > 1, which is impossible.", "misconception": "Forgetting that sinθ cannot exceed 1"}, {"option_key": "B", "hint": "n = 4 would require sinθ = 4λ/d = 4/3.33 = 1.2, which exceeds 1 and is physically impossible.", "misconception": "Rounding up instead of down for maximum integer order"}, {"option_key": "C", "hint": "n = 2 is an underestimate. Since d/λ = 3.33, the third order (n = 3) is still possible as sinθ = 0.9 < 1.", "misconception": "Incorrectly computing d/λ or taking too conservative an estimate"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The resolving power of a telescope increases with increase in the diameter of its objective lens.\nReason (R): The limit of resolution of a telescope is given by θ = 1.22λ/D, where D is the diameter of the objective.", "explanation": "The assertion is correct: increasing the diameter D of the objective lens decreases the minimum resolvable angle θ = 1.22λ/D, which means the telescope can resolve finer angular details, i.e., its resolving power increases. The reason is also correct: the formula θ = 1.22λ/D is indeed Rayleigh''s criterion for the limit of resolution of a telescope. Moreover, the reason correctly explains why the assertion is true — as D increases, θ decreases, so resolving power (which is 1/θ or D/1.22λ) increases.", "correct_answer": "A", "concept_tags": ["resolving-power-telescope", "rayleigh-criterion", "objective-diameter"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-13", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains the assertion: since θ = 1.22λ/D, increasing D decreases θ, hence increasing resolving power. The reason IS the explanation.", "misconception": "Failing to recognise the direct causal link between the formula and the assertion"}, {"option_key": "C", "hint": "The formula θ = 1.22λ/D is a well-established result (Rayleigh''s criterion) and is correct.", "misconception": "Doubting the validity of Rayleigh''s criterion"}, {"option_key": "D", "hint": "The assertion is a well-known fact: larger telescope objectives provide better angular resolution.", "misconception": "Confusing resolving power with magnifying power"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): In a single slit diffraction experiment, if the slit width is made very large compared to the wavelength, the diffraction pattern disappears and the screen is uniformly illuminated.\nReason (R): Diffraction effects are significant only when the size of the obstacle or aperture is comparable to the wavelength of light.", "explanation": "The assertion is correct: when the slit width ''a'' is much larger than the wavelength λ (a >> λ), the angular width of the central maximum 2λ/a becomes extremely small, essentially approaching zero. The diffraction fringes become so narrow and closely spaced that they are unobservable, and the light appears to travel in straight lines producing a uniformly illuminated region behind the slit (geometric shadow limit). The reason is also correct: diffraction is most prominent when the aperture size is of the order of the wavelength. Furthermore, the reason correctly explains the assertion — when ''a'' >> λ, the aperture is no longer comparable to the wavelength, so diffraction effects become negligible.", "correct_answer": "A", "concept_tags": ["slit-width-effect", "diffraction-condition", "wavelength-comparison"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-14", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason explains exactly why the diffraction pattern disappears: when the slit is much larger than λ, the aperture size is no longer comparable to the wavelength, making diffraction negligible. This is a direct explanation.", "misconception": "Not seeing the direct causal connection between the two statements"}, {"option_key": "C", "hint": "The reason is a well-established principle in wave optics and is correct. Diffraction is indeed most noticeable when aperture size is comparable to wavelength.", "misconception": "Incorrectly rejecting a fundamental diffraction principle"}, {"option_key": "D", "hint": "The assertion is correct. In the limit a >> λ, the angular spread 2λ/a → 0, and the pattern merges into uniform illumination.", "misconception": "Thinking diffraction always occurs regardless of slit width to wavelength ratio"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\nA. Resolving power of telescope\nB. Limit of resolution of microscope\nC. Angular width of central maximum (single slit)\nD. Condition for nth minimum (single slit)\n\nColumn II:\n1. a sin θ = nλ\n2. D/(1.22λ)\n3. λ/(2n sinθ)\n4. 2λ/a", "explanation": "A-2: The resolving power of a telescope is D/(1.22λ), where D is the objective diameter. B-3: The limit of resolution of a microscope is d_min = λ/(2n sinθ), where n sinθ is the numerical aperture. C-4: The angular width of the central maximum in single slit diffraction is 2λ/a. D-1: The condition for the nth minimum in single slit diffraction is a sin θ = nλ.", "correct_answer": "B", "concept_tags": ["resolving-power", "diffraction-formulae", "matching-type"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-15", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-3, C-4, D-1", "is_correct": true}, {"key": "C", "text": "A-3, B-2, C-1, D-4", "is_correct": false}, {"key": "D", "text": "A-4, B-1, C-2, D-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This incorrectly matches B (microscope limit of resolution) with 4 (2λ/a). The formula 2λ/a is the angular width of the central maximum, not the microscope resolution.", "misconception": "Confusing diffraction angular width formula with microscope resolution"}, {"option_key": "C", "hint": "A-3 would mean the telescope resolving power is λ/(2n sinθ), which is actually the microscope''s limit of resolution formula.", "misconception": "Swapping telescope and microscope formulae"}, {"option_key": "D", "hint": "This matching is entirely wrong. A-4 would assign the angular width formula to telescope resolving power.", "misconception": "Randomly assigning formulae without understanding their physical meaning"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\nA. Fresnel diffraction\nB. Fraunhofer diffraction\nC. Diffraction grating resolving power\nD. Width of central maximum on screen (single slit)\n\nColumn II:\n1. 2λD/a (where D is slit-to-screen distance)\n2. nN (where n is order and N is total number of slits)\n3. Source and screen at infinite distance\n4. Source or screen at finite distance", "explanation": "A-4: In Fresnel diffraction, either the source or the screen (or both) is at a finite distance from the diffracting element. B-3: In Fraunhofer diffraction, both source and screen are effectively at infinite distance (parallel incident rays and observation at infinity or focal plane of lens). C-2: The resolving power of a diffraction grating is nN, where n is the order of diffraction and N is the total number of slits. D-1: The linear width of the central maximum on the screen in single slit diffraction is 2λD/a, where D is the distance from the slit to the screen.", "correct_answer": "C", "concept_tags": ["fresnel-fraunhofer-comparison", "grating-resolving-power", "central-maximum-width"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-16", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-3, B-4, C-2, D-1", "is_correct": false}, {"key": "B", "text": "A-4, B-3, C-1, D-2", "is_correct": false}, {"key": "C", "text": "A-4, B-3, C-2, D-1", "is_correct": true}, {"key": "D", "text": "A-3, B-4, C-1, D-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A-3 says Fresnel diffraction has source at infinite distance, but that describes Fraunhofer diffraction. Fresnel involves finite distances.", "misconception": "Swapping Fresnel and Fraunhofer diffraction conditions"}, {"option_key": "B", "hint": "C-1 would mean grating resolving power is 2λD/a, which is actually the linear width of the central maximum, not resolving power.", "misconception": "Confusing the linear width formula with resolving power"}, {"option_key": "D", "hint": "This swaps Fresnel and Fraunhofer conditions and also swaps the resolving power and width formulae.", "misconception": "Multiple misidentifications of Fresnel/Fraunhofer and grating properties"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In single slit diffraction, the central maximum is twice as wide as the secondary maxima.", "explanation": "This statement is TRUE. In single slit Fraunhofer diffraction, the minima occur at angles given by a sinθ = nλ (n = ±1, ±2, ...). The central maximum extends from the first minimum on one side (θ = -λ/a) to the first minimum on the other side (θ = +λ/a), giving an angular width of 2λ/a. Each secondary maximum has an angular width of approximately λ/a (the spacing between consecutive minima). Therefore, the central maximum is twice the width of any secondary maximum.", "correct_answer": "A", "concept_tags": ["central-maximum", "secondary-maxima", "angular-width"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-17", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The central maximum spans from -λ/a to +λ/a (width = 2λ/a), while each secondary maximum spans about λ/a. The ratio is indeed 2:1.", "misconception": "Thinking all maxima in diffraction have equal width"}, {"option_key": "C", "hint": "This is a placeholder option.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The resolving power of a microscope increases when the wavelength of light used is increased.", "explanation": "This statement is FALSE. The resolving power of a microscope is given by RP = 2n sinθ/λ, where n sinθ is the numerical aperture. Since λ appears in the denominator, increasing the wavelength decreases the resolving power. To increase the resolving power of a microscope, one should use light of shorter wavelength (such as ultraviolet light or electron beams in electron microscopes).", "correct_answer": "B", "concept_tags": ["resolving-power-microscope", "wavelength-effect", "inverse-relationship"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-18", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Since RP = 2n sinθ/λ, increasing λ makes the denominator larger, reducing resolving power. Shorter wavelengths improve resolution.", "misconception": "Thinking wavelength and resolving power are directly proportional"}, {"option_key": "C", "hint": "This is a placeholder option.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The resolving power of a diffraction grating in the nth order with a total of N slits is given by RP = _____.", "explanation": "The resolving power of a diffraction grating is defined as RP = λ/Δλ, where Δλ is the minimum resolvable wavelength difference. According to the Rayleigh criterion applied to a diffraction grating, the resolving power equals the product of the order of diffraction (n) and the total number of slits (N): RP = nN. This means higher order diffraction and more slits both improve the ability to distinguish closely spaced spectral lines.", "correct_answer": "D", "concept_tags": ["diffraction-grating", "resolving-power-grating", "chromatic-resolving-power"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-19", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "N/n", "is_correct": false}, {"key": "B", "text": "n/N", "is_correct": false}, {"key": "C", "text": "(n + N)", "is_correct": false}, {"key": "D", "text": "nN", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "N/n would mean resolving power decreases with higher order, which contradicts the fact that higher order gives better spectral resolution.", "misconception": "Inverting the relationship between order number and resolving power"}, {"option_key": "B", "hint": "n/N would give a very small number for large N, but more slits should increase (not decrease) resolving power.", "misconception": "Swapping numerator and denominator"}, {"option_key": "C", "hint": "The resolving power is a product, not a sum. The formula RP = nN is derived from the condition for just resolving two wavelengths.", "misconception": "Confusing multiplication with addition in the formula"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "An astronomer is observing binary stars (two stars very close together) using two telescopes: Telescope P with an objective diameter of 100 cm and Telescope Q with an objective diameter of 50 cm. Both observations are made using light of wavelength 5500 Å. If Telescope P can just resolve the two stars, what can be said about the observation through Telescope Q?", "explanation": "The minimum angular separation that can be resolved is θ = 1.22λ/D. For Telescope P: θ_P = 1.22 × 5.5 × 10⁻⁷ / 1.0 = 6.71 × 10⁻⁷ rad. For Telescope Q: θ_Q = 1.22 × 5.5 × 10⁻⁷ / 0.5 = 1.342 × 10⁻⁶ rad. Since Q has half the diameter, its limit of resolution is twice that of P. If Telescope P just resolves the two stars (their angular separation equals θ_P), then Telescope Q cannot resolve them because its limit of resolution θ_Q = 2θ_P is larger than the actual angular separation of the stars. The two stars would appear as a single unresolved image through Telescope Q.", "correct_answer": "C", "concept_tags": ["rayleigh-criterion", "telescope-resolution", "scenario-based", "binary-stars"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-20", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Telescope Q will also just resolve the two stars", "is_correct": false}, {"key": "B", "text": "Telescope Q will resolve the stars more clearly than Telescope P", "is_correct": false}, {"key": "C", "text": "Telescope Q will not be able to resolve the two stars", "is_correct": true}, {"key": "D", "text": "The resolving power of both telescopes is the same since they use the same wavelength", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Telescope Q has a smaller objective (50 cm vs 100 cm), so its limit of resolution θ = 1.22λ/D is larger. It cannot match Telescope P''s resolving ability.", "misconception": "Ignoring the effect of objective diameter on resolution"}, {"option_key": "B", "hint": "A smaller objective diameter gives worse (not better) resolution. Telescope Q''s minimum resolvable angle is double that of Telescope P.", "misconception": "Thinking smaller telescopes have better resolution"}, {"option_key": "D", "hint": "Resolving power depends on both λ and D. Although the wavelength is the same, the different diameters give different resolving powers: RP = D/(1.22λ).", "misconception": "Thinking resolving power depends only on wavelength"}]}}]'::jsonb, 'deploy-2026-03-05-b14');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In Young''s double slit experiment, the fringe width is given by:", "explanation": "The fringe width in Young''s double slit experiment is given by the formula beta = lambdaD/d, where lambda is the wavelength of light, D is the distance between the slits and the screen, and d is the separation between the two slits. This formula is derived from the geometry of the experiment and the condition for constructive interference.", "correct_answer": "A", "concept_tags": ["fringe-width", "ydse-formula", "wave-optics"], "payload": {"question_id": "cuet-phy-waveopt-interference-01", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "beta = lambdaD/d", "is_correct": true}, {"key": "B", "text": "beta = lambdad/D", "is_correct": false}, {"key": "C", "text": "beta = d/lambdaD", "is_correct": false}, {"key": "D", "text": "beta = D/lambdad", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This formula has d and D interchanged. Fringe width increases with screen distance D and decreases with slit separation d, so D must be in the numerator and d in the denominator.", "misconception": "Interchanging the roles of slit separation and screen distance"}, {"option_key": "C", "hint": "This places wavelength in the denominator. Since fringe width increases with wavelength, lambda must be in the numerator.", "misconception": "Inverting the fringe width formula"}, {"option_key": "D", "hint": "This formula has all three quantities incorrectly placed. Recall that fringe width is directly proportional to both lambda and D.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "For sustained interference of light, the two sources must be:", "explanation": "Sustained (or stable) interference requires coherent sources, meaning the two sources must emit light waves of the same frequency and maintain a constant phase difference. Incoherent sources produce randomly varying phase differences, causing the interference pattern to change rapidly and average out, making it invisible.", "correct_answer": "B", "concept_tags": ["coherent-sources", "sustained-interference", "conditions-for-interference"], "payload": {"question_id": "cuet-phy-waveopt-interference-02", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "Of different frequencies with random phase", "is_correct": false}, {"key": "B", "text": "Coherent, i.e., having the same frequency and a constant phase difference", "is_correct": true}, {"key": "C", "text": "Very bright and of the same intensity", "is_correct": false}, {"key": "D", "text": "Polarised in mutually perpendicular directions", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Different frequencies mean the phase difference changes continuously, so no sustained fringe pattern can form.", "misconception": "Thinking that any two light sources can produce sustained interference"}, {"option_key": "C", "hint": "Equal intensity is not a necessary condition for interference. Unequal intensities still produce interference, only with reduced contrast (non-zero minima).", "misconception": "Confusing intensity condition with coherence condition"}, {"option_key": "D", "hint": "Perpendicular polarisations would prevent interference entirely. For interference, the waves should have the same state of polarisation, not perpendicular.", "misconception": "Confusing polarisation with coherence requirements"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In Young''s double slit experiment, if the slit separation d is doubled while keeping all other parameters constant, the fringe width will:", "explanation": "The fringe width beta = lambdaD/d. If d is doubled, beta becomes lambdaD/(2d) = beta/2. So the fringe width is halved. Increasing the slit separation brings the fringes closer together.", "correct_answer": "C", "concept_tags": ["fringe-width", "slit-separation", "ydse-parameters"], "payload": {"question_id": "cuet-phy-waveopt-interference-03", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "Become double", "is_correct": false}, {"key": "B", "text": "Remain the same", "is_correct": false}, {"key": "C", "text": "Become half", "is_correct": true}, {"key": "D", "text": "Become four times", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Doubling d would double the fringe width only if d were in the numerator. Since beta = lambdaD/d, d is in the denominator, so increasing d decreases beta.", "misconception": "Thinking fringe width is directly proportional to slit separation"}, {"option_key": "B", "hint": "Fringe width depends inversely on slit separation, so changing d must change beta.", "misconception": "Ignoring the dependence of fringe width on slit separation"}, {"option_key": "D", "hint": "A fourfold change would require squaring, but the relationship is beta inversely proportional to d (first power), not d squared.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The path difference between two waves reaching a point on the screen in Young''s experiment for the third bright fringe is:", "explanation": "For bright fringes (constructive interference), the path difference = n*lambda, where n is the order of the fringe. For the third bright fringe, n = 3, so the path difference = 3*lambda.", "correct_answer": "D", "concept_tags": ["path-difference", "bright-fringe", "constructive-interference"], "payload": {"question_id": "cuet-phy-waveopt-interference-04", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "lambda/2", "is_correct": false}, {"key": "B", "text": "lambda", "is_correct": false}, {"key": "C", "text": "5*lambda/2", "is_correct": false}, {"key": "D", "text": "3*lambda", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "lambda/2 is the path difference for the first dark fringe (first minimum), not a bright fringe.", "misconception": "Confusing conditions for bright and dark fringes"}, {"option_key": "B", "hint": "lambda corresponds to the first bright fringe (n = 1), not the third.", "misconception": "Confusing fringe order"}, {"option_key": "C", "hint": "5*lambda/2 is the path difference for the third dark fringe (n = 3 in the dark fringe formula (2n-1)*lambda/2), not the third bright fringe.", "misconception": "Using the dark fringe formula instead of the bright fringe formula"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In Young''s double slit experiment, two slits are separated by 0.5 mm and the screen is placed 1 m away. If the wavelength of light used is 500 nm, the fringe width is:", "explanation": "Using beta = lambdaD/d = (500 x 10^-9 x 1) / (0.5 x 10^-3) = (5 x 10^-7) / (5 x 10^-4) = 1 x 10^-3 m = 1 mm. The fringe width is 1 mm.", "correct_answer": "B", "concept_tags": ["fringe-width", "numerical-problem", "ydse-formula"], "payload": {"question_id": "cuet-phy-waveopt-interference-05", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "0.5 mm", "is_correct": false}, {"key": "B", "text": "1 mm", "is_correct": true}, {"key": "C", "text": "2 mm", "is_correct": false}, {"key": "D", "text": "0.1 mm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Check your calculation. 0.5 mm results from an error such as using d = 1 mm instead of 0.5 mm.", "misconception": "Arithmetic error in substitution"}, {"option_key": "C", "hint": "2 mm would result from using d = 0.25 mm instead of 0.5 mm. Recheck the slit separation value.", "misconception": "Incorrect unit conversion or value substitution"}, {"option_key": "D", "hint": "0.1 mm is 10 times too small. Verify that all units are converted to SI before substituting into the formula.", "misconception": "Unit conversion error (using mm instead of m for wavelength)"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In Young''s experiment, if the intensity of light from each slit is I_0, the intensity at a point where the phase difference between the two waves is pi/2 is:", "explanation": "The resultant intensity in YDSE is given by I = 4*I_0*cos^2(phi/2). When phi = pi/2, we get I = 4*I_0*cos^2(pi/4) = 4*I_0*(1/sqrt(2))^2 = 4*I_0*(1/2) = 2*I_0.", "correct_answer": "C", "concept_tags": ["intensity-distribution", "phase-difference", "interference-pattern"], "payload": {"question_id": "cuet-phy-waveopt-interference-06", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "4*I_0", "is_correct": false}, {"key": "B", "text": "I_0", "is_correct": false}, {"key": "C", "text": "2*I_0", "is_correct": true}, {"key": "D", "text": "0", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "4*I_0 is the maximum intensity at a bright fringe where phi = 0 (perfectly constructive interference), not where phi = pi/2.", "misconception": "Thinking any non-zero phase difference gives maximum intensity"}, {"option_key": "B", "hint": "I_0 would require cos^2(phi/2) = 1/4, which corresponds to phi = 2*pi/3, not pi/2.", "misconception": "Incorrectly evaluating the cosine function"}, {"option_key": "D", "hint": "Zero intensity occurs at phi = pi (complete destructive interference). At phi = pi/2 the waves are partially in phase and the intensity is non-zero.", "misconception": "Confusing phi = pi/2 with destructive interference"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In Young''s double slit experiment, if the entire apparatus is immersed in a liquid of refractive index mu, the fringe width will:", "explanation": "In a medium of refractive index mu, the wavelength becomes lambda'' = lambda/mu. Since fringe width beta = lambda*D/d, the new fringe width beta'' = (lambda/mu)*D/d = beta/mu. Since mu > 1, the fringe width decreases.", "correct_answer": "A", "concept_tags": ["fringe-width", "refractive-index", "ydse-in-medium"], "payload": {"question_id": "cuet-phy-waveopt-interference-07", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "Decrease by a factor of mu", "is_correct": true}, {"key": "B", "text": "Increase by a factor of mu", "is_correct": false}, {"key": "C", "text": "Remain unchanged", "is_correct": false}, {"key": "D", "text": "Decrease by a factor of mu^2", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Wavelength decreases in a denser medium, so fringe width must decrease, not increase.", "misconception": "Thinking wavelength increases in a denser medium"}, {"option_key": "C", "hint": "Fringe width depends on wavelength, which changes in a medium. The frequency remains unchanged, but the wavelength changes.", "misconception": "Forgetting that wavelength changes in a medium"}, {"option_key": "D", "hint": "The relationship is linear: beta is proportional to lambda, and lambda is proportional to 1/mu. There is no squaring involved.", "misconception": "Incorrectly squaring the refractive index"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ratio of the maximum to minimum intensity in an interference pattern when two coherent sources have intensity ratio 4:1 is:", "explanation": "If I_1/I_2 = 4/1, then sqrt(I_1)/sqrt(I_2) = 2/1. Maximum intensity I_max = (sqrt(I_1) + sqrt(I_2))^2 = (2 + 1)^2 = 9. Minimum intensity I_min = (sqrt(I_1) - sqrt(I_2))^2 = (2 - 1)^2 = 1. Therefore, I_max/I_min = 9:1.", "correct_answer": "D", "concept_tags": ["intensity-ratio", "constructive-destructive-interference", "amplitude-superposition"], "payload": {"question_id": "cuet-phy-waveopt-interference-08", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "4:1", "is_correct": false}, {"key": "B", "text": "5:3", "is_correct": false}, {"key": "C", "text": "25:9", "is_correct": false}, {"key": "D", "text": "9:1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "4:1 is the ratio of the individual source intensities, not the maximum-to-minimum ratio. You need to use amplitude addition and subtraction.", "misconception": "Confusing source intensity ratio with fringe intensity ratio"}, {"option_key": "B", "hint": "5:3 would come from adding and subtracting intensities directly (4+1):(4-1), but intensities do not add this way in interference. Amplitudes add, and intensity is proportional to amplitude squared.", "misconception": "Adding intensities directly instead of amplitudes"}, {"option_key": "C", "hint": "25:9 would result from an incorrect formula. The correct approach uses (sqrt(I_1) + sqrt(I_2))^2 / (sqrt(I_1) - sqrt(I_2))^2.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In thin film interference, an oil film of thickness t and refractive index mu appears bright in reflected light when (for near-normal incidence):", "explanation": "In thin film interference in reflected light, there is an extra phase change of pi (equivalent to lambda/2 path difference) at the top surface where light reflects from a denser medium. The condition for constructive interference (bright film) becomes 2*mu*t = (2n - 1)*lambda/2, i.e., the optical path difference 2*mu*t equals an odd multiple of lambda/2.", "correct_answer": "B", "concept_tags": ["thin-film-interference", "reflected-light", "optical-path-difference"], "payload": {"question_id": "cuet-phy-waveopt-interference-09", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "2*mu*t = n*lambda", "is_correct": false}, {"key": "B", "text": "2*mu*t = (2n - 1)*lambda/2", "is_correct": true}, {"key": "C", "text": "2*t = n*lambda", "is_correct": false}, {"key": "D", "text": "mu*t = n*lambda", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "2*mu*t = n*lambda is the condition for destructive interference (dark) in reflected light, because the additional phase change at the top surface shifts the constructive condition.", "misconception": "Forgetting the extra phase change of pi at the denser medium reflection"}, {"option_key": "C", "hint": "This formula ignores the refractive index mu. The optical path inside the film is 2*mu*t, not 2*t.", "misconception": "Ignoring the refractive index in thin film calculations"}, {"option_key": "D", "hint": "The light traverses the film twice (down and back up), so the path is 2*mu*t, not mu*t.", "misconception": "Forgetting the factor of 2 for double traversal"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In Young''s double slit experiment with slit separation 1 mm and screen distance 1 m, two wavelengths lambda_1 = 600 nm and lambda_2 = 480 nm are used. The minimum distance from the central maximum where bright fringes of both wavelengths coincide is:", "explanation": "For the bright fringes to coincide, n_1*lambda_1 = n_2*lambda_2 (same path difference). So n_1*600 = n_2*480, giving n_1/n_2 = 480/600 = 4/5. The minimum integers satisfying this are n_1 = 4 and n_2 = 5. The distance from the central maximum = n_1*lambda_1*D/d = 4 * 600 x 10^-9 * 1 / (1 x 10^-3) = 2400 x 10^-6 m = 2.4 mm.", "correct_answer": "C", "concept_tags": ["ydse-two-wavelengths", "fringe-coincidence", "numerical-problem"], "payload": {"question_id": "cuet-phy-waveopt-interference-10", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "analyze", "options": [{"key": "A", "text": "1.2 mm", "is_correct": false}, {"key": "B", "text": "1.8 mm", "is_correct": false}, {"key": "C", "text": "2.4 mm", "is_correct": true}, {"key": "D", "text": "3.0 mm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1.2 mm corresponds to n_1 = 2 for lambda_1. Check whether n_2 is an integer: 2 x 600/480 = 2.5, which is not an integer, so fringes do not coincide here.", "misconception": "Not checking if both fringe orders are integers"}, {"option_key": "B", "hint": "1.8 mm corresponds to n_1 = 3 for lambda_1. Check: n_2 = 3 x 600/480 = 3.75, which is not an integer.", "misconception": null}, {"option_key": "D", "hint": "3.0 mm corresponds to n_1 = 5 for lambda_1. While n_2 = 5 x 600/480 = 6.25 is not an integer, the minimum coincidence occurs at n_1 = 4, n_2 = 5.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In Newton''s rings experiment, the radius of the n-th dark ring is proportional to:", "explanation": "In Newton''s rings, the radius of the n-th dark ring is given by r_n = sqrt(n*lambda*R), where R is the radius of curvature of the plano-convex lens and lambda is the wavelength. Therefore, r_n is proportional to sqrt(n).", "correct_answer": "A", "concept_tags": ["newtons-rings", "dark-ring-radius", "thin-film-interference"], "payload": {"question_id": "cuet-phy-waveopt-interference-11", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "sqrt(n)", "is_correct": true}, {"key": "B", "text": "n", "is_correct": false}, {"key": "C", "text": "n^2", "is_correct": false}, {"key": "D", "text": "1/n", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The radius is proportional to sqrt(n), not n. The area enclosed by the ring is proportional to n, which may cause confusion.", "misconception": "Confusing ring radius with ring area proportionality"}, {"option_key": "C", "hint": "n^2 dependence would mean rings spread out rapidly, which contradicts the observation that Newton''s rings get closer together for higher orders.", "misconception": null}, {"option_key": "D", "hint": "1/n would mean higher-order rings have smaller radii, which is physically incorrect. Higher-order rings are always farther from the centre.", "misconception": "Inverting the relationship between ring number and radius"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "When white light is used in Young''s double slit experiment, the central fringe is:", "explanation": "At the central position, the path difference is zero for all wavelengths. Therefore, all wavelengths undergo constructive interference at the central point, and the central fringe appears white. Away from the centre, different wavelengths produce maxima at different positions, leading to coloured fringes.", "correct_answer": "D", "concept_tags": ["white-light-interference", "central-fringe", "ydse"], "payload": {"question_id": "cuet-phy-waveopt-interference-12", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "Red", "is_correct": false}, {"key": "B", "text": "Violet", "is_correct": false}, {"key": "C", "text": "Dark", "is_correct": false}, {"key": "D", "text": "White", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Red fringes appear at positions where only red light undergoes constructive interference. The central fringe has zero path difference for all colours, not just red.", "misconception": "Thinking only one colour dominates at the centre"}, {"option_key": "B", "hint": "Similar to red, violet alone does not dominate the central position. All wavelengths constructively interfere at zero path difference.", "misconception": null}, {"option_key": "C", "hint": "A dark fringe would require destructive interference, which cannot occur at zero path difference where all wavelengths are in phase.", "misconception": "Thinking superposition of all colours causes cancellation"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): In Young''s double slit experiment, the fringe pattern shifts when a thin transparent glass plate is introduced in the path of one of the beams. Reason (R): The glass plate introduces an additional optical path difference because light travels slower in glass than in air.", "explanation": "Assertion is correct: introducing a glass plate of thickness t and refractive index mu in one beam introduces an extra optical path of (mu - 1)*t, shifting the central fringe to a new position. Reason is also correct: light travels slower in glass (speed = c/mu), so the optical path length increases. The Reason correctly explains the Assertion because it is precisely because of the increased optical path (due to slower speed in glass) that the fringe pattern shifts.", "correct_answer": "A", "concept_tags": ["glass-plate-in-ydse", "optical-path-difference", "fringe-shift"], "payload": {"question_id": "cuet-phy-waveopt-interference-13", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains the assertion. The fringe shift occurs precisely because the glass introduces an additional optical path due to the reduced speed of light in glass.", "misconception": "Failing to see the causal link between slower light speed and fringe shift"}, {"option_key": "C", "hint": "The reason is factually correct. Light does travel slower in glass (v = c/mu, and mu > 1 for glass), increasing the optical path.", "misconception": "Thinking the speed of light does not change in glass"}, {"option_key": "D", "hint": "The assertion is correct. Inserting a glass plate in one beam path is a well-known method to shift the fringe pattern in YDSE.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Two independent laser sources of the same frequency cannot produce a sustained interference pattern. Reason (R): For sustained interference, the two sources must be derived from the same parent source to maintain a constant phase relationship.", "explanation": "Assertion is correct: even two lasers of nominally the same frequency have independent, randomly fluctuating phases. Over time, the phase difference varies, and the interference pattern averages out, so no sustained pattern is observed. Reason is also correct and is the correct explanation: deriving both beams from a single source (as in YDSE) ensures a constant phase difference, which is essential for a stable interference pattern.", "correct_answer": "A", "concept_tags": ["coherent-sources", "independent-sources", "sustained-interference", "laser-coherence"], "payload": {"question_id": "cuet-phy-waveopt-interference-14", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly addresses why independent sources fail: the lack of a common parent source means no constant phase relationship. This is exactly why the assertion is true.", "misconception": "Not seeing the direct causal connection between same parent source and sustained interference"}, {"option_key": "C", "hint": "The reason is correct. Deriving two beams from a single source (e.g., by splitting) does maintain coherence, which is a fundamental principle of wave optics.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct. Even high-quality lasers have independent phase fluctuations, making sustained interference impossible without deriving beams from the same source.", "misconception": "Thinking that same-frequency lasers are automatically coherent with each other"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\nA. Path difference = n*lambda\nB. Path difference = (2n - 1)*lambda/2\nC. Phase difference = 0\nD. Phase difference = pi\n\nColumn II:\n1. Destructive interference\n2. Constructive interference\n3. Maximum intensity\n4. Minimum (zero) intensity", "explanation": "A. Path difference = n*lambda corresponds to constructive interference (2). B. Path difference = (2n-1)*lambda/2 corresponds to destructive interference (1). C. Phase difference = 0 means the waves are perfectly in phase, giving maximum intensity (3). D. Phase difference = pi means the waves are completely out of phase, giving minimum/zero intensity (4). So the correct matching is A-2, B-1, C-3, D-4.", "correct_answer": "D", "concept_tags": ["path-difference", "phase-difference", "constructive-destructive-interference"], "payload": {"question_id": "cuet-phy-waveopt-interference-15", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "A-1, B-2, C-4, D-3", "is_correct": false}, {"key": "B", "text": "A-2, B-1, C-4, D-3", "is_correct": false}, {"key": "C", "text": "A-3, B-4, C-2, D-1", "is_correct": false}, {"key": "D", "text": "A-2, B-1, C-3, D-4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This reverses constructive and destructive interference conditions. Path difference n*lambda gives constructive (not destructive) interference.", "misconception": "Confusing conditions for constructive and destructive interference"}, {"option_key": "B", "hint": "C-4 and D-3 are reversed. Phase difference 0 means waves are in phase (maximum intensity), while phase difference pi means they cancel (minimum intensity).", "misconception": "Confusing zero phase difference with minimum intensity"}, {"option_key": "C", "hint": "Path difference n*lambda leads to constructive interference, not directly maximum intensity as a separate concept. Check each match individually.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\nA. Fringe width (beta) when wavelength is doubled\nB. Fringe width when slit separation is halved\nC. Fringe width when screen distance is tripled\nD. Fringe width when experiment is done in water (mu = 4/3)\n\nColumn II:\n1. beta becomes 3*beta\n2. beta becomes 2*beta\n3. beta becomes (3/4)*beta\n4. beta becomes 2*beta", "explanation": "Using beta = lambda*D/d: A. lambda doubled: beta'' = 2*lambda*D/d = 2*beta (matches 2). B. d halved: beta'' = lambda*D/(d/2) = 2*beta (matches 4). C. D tripled: beta'' = lambda*3D/d = 3*beta (matches 1). D. In water (mu = 4/3): lambda'' = lambda/mu = 3*lambda/4, so beta'' = (3/4)*beta (matches 3). Correct matching: A-2, B-4, C-1, D-3.", "correct_answer": "C", "concept_tags": ["fringe-width-variations", "ydse-parameters", "refractive-index-effect"], "payload": {"question_id": "cuet-phy-waveopt-interference-16", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-1, B-2, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-3, C-1, D-4", "is_correct": false}, {"key": "C", "text": "A-2, B-4, C-1, D-3", "is_correct": true}, {"key": "D", "text": "A-4, B-2, C-3, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Doubling lambda gives 2*beta, not 3*beta. Check the proportionality: beta is directly proportional to lambda.", "misconception": "Incorrect proportionality assessment"}, {"option_key": "B", "hint": "Halving d gives 2*beta (matches 4), not (3/4)*beta (which is 3). Check: beta is inversely proportional to d.", "misconception": "Confusing inverse and direct proportionality with slit separation"}, {"option_key": "D", "hint": "This option assigns completely incorrect factors. Systematically apply beta = lambda*D/d with each change separately.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In Young''s double slit experiment, the fringe width is directly proportional to the wavelength of light used.", "explanation": "This statement is TRUE. From the fringe width formula beta = lambda*D/d, we can see that beta is directly proportional to lambda (keeping D and d constant). If the wavelength increases, the fringe width increases proportionally, and if the wavelength decreases, the fringe width decreases proportionally.", "correct_answer": "A", "concept_tags": ["fringe-width", "wavelength-dependence", "ydse-formula"], "payload": {"question_id": "cuet-phy-waveopt-interference-17", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The formula beta = lambda*D/d clearly shows lambda in the numerator with a power of 1, confirming a directly proportional relationship.", "misconception": "Thinking fringe width is inversely proportional to wavelength"}, {"option_key": "C", "hint": "This is not a valid option for this question.", "misconception": null}, {"option_key": "D", "hint": "This is not a valid option for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "In the interference pattern produced by two coherent sources, energy is destroyed at the positions of dark fringes.", "explanation": "This statement is FALSE. Energy is NOT destroyed at dark fringes. The principle of conservation of energy holds. In interference, energy is redistributed: the energy missing from dark fringes (minima) appears at the bright fringes (maxima). The total energy remains constant; it is merely redistributed in space.", "correct_answer": "B", "concept_tags": ["energy-conservation", "interference-pattern", "energy-redistribution"], "payload": {"question_id": "cuet-phy-waveopt-interference-18", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Energy can neither be created nor destroyed. In interference, energy from dark fringes is redistributed to bright fringes, conserving total energy.", "misconception": "Thinking that zero intensity at minima means energy is lost"}, {"option_key": "C", "hint": "This is not a valid option for this question.", "misconception": null}, {"option_key": "D", "hint": "This is not a valid option for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "In Young''s double slit experiment, if the two slits are illuminated by monochromatic light of wavelength 600 nm with slit separation 0.3 mm and screen distance 1.5 m, the distance between the 4th bright fringe and the 4th dark fringe on the same side of the central maximum is _____.", "explanation": "Fringe width beta = lambda*D/d = (600 x 10^-9 x 1.5) / (0.3 x 10^-3) = 9 x 10^-7 / 3 x 10^-4 = 3 x 10^-3 m = 3 mm. Position of the 4th bright fringe = 4*beta = 12 mm. Position of the 4th dark fringe = (4 - 1/2)*beta = 3.5*beta = 10.5 mm. The distance between them = 12 - 10.5 = 1.5 mm = beta/2.", "correct_answer": "B", "concept_tags": ["fringe-position", "bright-dark-fringe-distance", "numerical-problem"], "payload": {"question_id": "cuet-phy-waveopt-interference-19", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "3 mm", "is_correct": false}, {"key": "B", "text": "1.5 mm", "is_correct": true}, {"key": "C", "text": "0.75 mm", "is_correct": false}, {"key": "D", "text": "6 mm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3 mm is the fringe width itself. The distance between adjacent bright and dark fringes (of the same order, same side) is beta/2, not beta.", "misconception": "Confusing fringe width with the bright-dark fringe separation"}, {"option_key": "C", "hint": "0.75 mm = beta/4, which has no standard significance in YDSE fringe separation. The separation between the n-th bright and n-th dark fringe on the same side is always beta/2.", "misconception": null}, {"option_key": "D", "hint": "6 mm = 2*beta. This does not correspond to any standard fringe separation. Recalculate the positions of the 4th bright and 4th dark fringes.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A student performs Young''s double slit experiment in the laboratory. The slit separation is 0.2 mm and the screen is 1 m away. Using a sodium lamp (lambda = 589 nm), the student observes a clear fringe pattern. The student then covers one of the slits. Which of the following correctly describes what happens to the pattern on the screen?", "explanation": "When one slit is blocked, there is no longer two-source interference. Instead, light passes through only a single slit, producing a single-slit diffraction pattern. This pattern has a broad central maximum with much wider and less distinct secondary maxima, and the sharp equidistant interference fringes disappear. The central diffraction maximum is much broader than the interference fringes, and the intensity distribution changes from the cos^2 modulation of YDSE to the sinc^2 pattern of single-slit diffraction.", "correct_answer": "C", "concept_tags": ["ydse-single-slit", "diffraction-vs-interference", "experimental-observation"], "payload": {"question_id": "cuet-phy-waveopt-interference-20", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "evaluate", "options": [{"key": "A", "text": "The fringe width doubles because only one slit contributes", "is_correct": false}, {"key": "B", "text": "The screen becomes completely dark", "is_correct": false}, {"key": "C", "text": "The interference fringes disappear and a broad single-slit diffraction pattern is observed", "is_correct": true}, {"key": "D", "text": "The fringes become brighter but otherwise remain unchanged", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The fringe width formula beta = lambda*D/d applies only to double-slit interference. With one slit covered, there is no two-source interference and hence no interference fringes to have a ''width''.", "misconception": "Thinking double-slit interference pattern persists with one slit blocked"}, {"option_key": "B", "hint": "Light still passes through the open slit and illuminates the screen. One slit produces a diffraction pattern, not darkness.", "misconception": "Thinking interference is needed for any light to reach the screen"}, {"option_key": "D", "hint": "The pattern fundamentally changes from equidistant interference fringes to a broad diffraction envelope. The two patterns are qualitatively different.", "misconception": "Not distinguishing between interference and diffraction patterns"}]}}]'::jsonb, 'deploy-2026-03-05-b14');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The phenomenon of polarisation of light proves that light is:", "explanation": "Polarisation is the phenomenon in which the vibrations of the electric field vector of a light wave are confined to a single plane. Only transverse waves can be polarised because longitudinal waves oscillate along the direction of propagation and cannot be restricted to a single plane. Since light can be polarised, it proves that light is a transverse wave.", "correct_answer": "A", "concept_tags": ["polarisation", "transverse-wave", "nature-of-light"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-01", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "A transverse wave", "is_correct": true}, {"key": "B", "text": "A longitudinal wave", "is_correct": false}, {"key": "C", "text": "Both transverse and longitudinal", "is_correct": false}, {"key": "D", "text": "Neither transverse nor longitudinal", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Longitudinal waves (like sound in air) oscillate along the direction of propagation. Such waves cannot exhibit polarisation because there is no perpendicular component to restrict.", "misconception": "Confusing longitudinal and transverse wave properties"}, {"option_key": "C", "hint": "If light were longitudinal, it could not be polarised. Polarisation is exclusively a property of transverse waves.", "misconception": null}, {"option_key": "D", "hint": "Light is a well-characterised electromagnetic wave. Polarisation specifically identifies it as transverse.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "When unpolarised light of intensity I₀ passes through a single Polaroid, the intensity of the transmitted light is:", "explanation": "Unpolarised light has electric field vibrations in all directions perpendicular to propagation. A Polaroid transmits only the component of vibration along its pass axis. On averaging cos²θ over all angles (0 to 2π), the average value of cos²θ is 1/2. Therefore, the transmitted intensity is I₀/2.", "correct_answer": "B", "concept_tags": ["polaroid", "unpolarised-light", "intensity-reduction"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-02", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "I₀", "is_correct": false}, {"key": "B", "text": "I₀/2", "is_correct": true}, {"key": "C", "text": "I₀/4", "is_correct": false}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "If the full intensity were transmitted, the Polaroid would have no effect at all. A Polaroid always absorbs the component of light perpendicular to its pass axis.", "misconception": "Assuming Polaroid transmits all light"}, {"option_key": "C", "hint": "I₀/4 would be the result after passing through two crossed Polaroids with an intermediate Polaroid at 45°. A single Polaroid transmits I₀/2.", "misconception": "Confusing single Polaroid with two-Polaroid system"}, {"option_key": "D", "hint": "Zero intensity would occur only if the light were already polarised perpendicular to the Polaroid''s pass axis. Unpolarised light always has some component along the pass axis.", "misconception": "Confusing unpolarised light with cross-polarised light"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Brewster''s law, the polarising angle iₚ for a medium of refractive index μ is given by:", "explanation": "Brewster''s law states that when light is incident on a transparent surface at the polarising angle iₚ, the reflected light is completely plane polarised. The relationship is tan iₚ = μ, where μ is the refractive index of the medium. At this angle, the reflected and refracted rays are perpendicular to each other.", "correct_answer": "C", "concept_tags": ["brewster-law", "polarising-angle", "refractive-index"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-03", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "sin iₚ = μ", "is_correct": false}, {"key": "B", "text": "cos iₚ = μ", "is_correct": false}, {"key": "C", "text": "tan iₚ = μ", "is_correct": true}, {"key": "D", "text": "cot iₚ = μ", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "sin iₚ = μ is Snell''s law form and would require μ ≤ 1 for any real angle, which is not generally true for denser media.", "misconception": "Confusing Brewster''s law with Snell''s law"}, {"option_key": "B", "hint": "cos iₚ = μ would also require μ ≤ 1 and has no physical basis in the derivation of Brewster''s condition.", "misconception": null}, {"option_key": "D", "hint": "cot iₚ = μ is the inverse of the correct relation. Brewster''s law uses tangent, not cotangent.", "misconception": "Inverting the Brewster''s law relation"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Polaroid sunglasses reduce glare from surfaces because they:", "explanation": "Light reflected from horizontal surfaces such as roads and water is partially polarised with the electric field vibrating predominantly in the horizontal plane. Polaroid sunglasses have their pass axis oriented vertically, which blocks this horizontally polarised glare while transmitting the vertically polarised component of light from other sources, thereby reducing glare without making everything dark.", "correct_answer": "D", "concept_tags": ["polaroid", "applications-of-polarisation", "glare-reduction"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-04", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "Absorb all light equally, reducing overall brightness", "is_correct": false}, {"key": "B", "text": "Reflect all incoming light back towards the source", "is_correct": false}, {"key": "C", "text": "Diffract the light around the edges of the lens", "is_correct": false}, {"key": "D", "text": "Block the horizontally polarised component of reflected light", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "If they absorbed all light equally, they would just be tinted lenses. Polaroid lenses specifically reduce glare by selectively blocking polarised light.", "misconception": "Confusing Polaroid with ordinary tinted glass"}, {"option_key": "B", "hint": "Polaroid lenses do not reflect light; they absorb one polarisation component while transmitting the other.", "misconception": null}, {"option_key": "C", "hint": "Diffraction is the bending of light around obstacles and is unrelated to glare reduction by Polaroid lenses.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Plane polarised light of intensity I₀ passes through a Polaroid whose pass axis makes an angle of 60° with the plane of polarisation. The intensity of the transmitted light is:", "explanation": "According to Malus''s law, when plane polarised light of intensity I₀ passes through a Polaroid (analyser), the transmitted intensity is I = I₀cos²θ, where θ is the angle between the polarisation direction and the pass axis of the analyser. Here θ = 60°, so I = I₀cos²60° = I₀ × (1/2)² = I₀/4.", "correct_answer": "B", "concept_tags": ["malus-law", "plane-polarised-light", "intensity"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-05", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "I₀/2", "is_correct": false}, {"key": "B", "text": "I₀/4", "is_correct": true}, {"key": "C", "text": "3I₀/4", "is_correct": false}, {"key": "D", "text": "I₀/8", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "I₀/2 would be the result for θ = 45° (since cos²45° = 1/2), not for θ = 60°.", "misconception": "Using wrong angle value or confusing with single Polaroid on unpolarised light"}, {"option_key": "C", "hint": "3I₀/4 = I₀ × cos²30°, which would apply if θ = 30°, not 60°. Check the angle carefully.", "misconception": "Using the complementary angle instead of the given angle"}, {"option_key": "D", "hint": "I₀/8 does not correspond to cos²θ for any standard angle. For θ = 60°, cos²60° = (1/2)² = 1/4.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The Brewster''s angle for a glass surface of refractive index 1.5 is approximately:", "explanation": "Using Brewster''s law: tan iₚ = μ = 1.5. Therefore iₚ = tan⁻¹(1.5). Computing: tan⁻¹(1.5) ≈ 56.3°. At this angle, the reflected light is completely plane polarised and the reflected and refracted rays are perpendicular to each other.", "correct_answer": "C", "concept_tags": ["brewster-angle", "refractive-index", "polarisation-by-reflection"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-06", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "33.7°", "is_correct": false}, {"key": "B", "text": "45°", "is_correct": false}, {"key": "C", "text": "56.3°", "is_correct": true}, {"key": "D", "text": "60°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "33.7° is the complement of the Brewster angle (90° - 56.3°). This is actually the angle of refraction at Brewster''s angle, not the Brewster angle itself.", "misconception": "Confusing the angle of refraction with the polarising angle"}, {"option_key": "B", "hint": "45° would be the Brewster angle only if μ = tan 45° = 1, which would mean both media have the same refractive index.", "misconception": "Assuming Brewster''s angle is always 45°"}, {"option_key": "D", "hint": "tan 60° = √3 ≈ 1.732, which corresponds to μ = √3, not μ = 1.5.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "At Brewster''s angle, the angle between the reflected ray and the refracted ray is:", "explanation": "At Brewster''s angle, the reflected ray and the refracted ray are perpendicular to each other, i.e., the angle between them is 90°. This is because at the polarising angle iₚ, we have iₚ + r = 90° (where r is the angle of refraction). Since the reflected ray makes angle iₚ with the normal and the refracted ray makes angle r with the normal, the angle between the reflected and refracted rays is iₚ + r = 90°. Wait -- more precisely, the reflected ray is on the same side as the incident ray making angle iₚ with the normal, while the refracted ray is on the other side making angle r with the normal. The angle between them measured from the surface is (90° - iₚ) + (90° - r) = 180° - (iₚ + r) = 180° - 90° = 90°.", "correct_answer": "A", "concept_tags": ["brewster-angle", "reflected-refracted-perpendicular", "polarisation-by-reflection"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-07", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "90°", "is_correct": true}, {"key": "B", "text": "60°", "is_correct": false}, {"key": "C", "text": "180°", "is_correct": false}, {"key": "D", "text": "It depends on the refractive index of the medium", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "60° would be the angle only for a specific refractive index, but the perpendicularity of reflected and refracted rays at Brewster''s angle holds for all media.", "misconception": null}, {"option_key": "C", "hint": "180° would mean the reflected and refracted rays are in the same direction, which is physically impossible since they are on opposite sides of the interface.", "misconception": null}, {"option_key": "D", "hint": "While the Brewster angle itself depends on μ, the angle between reflected and refracted rays at Brewster''s angle is always 90°, regardless of the medium.", "misconception": "Thinking the 90° relationship varies with material"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two Polaroids P₁ and P₂ are placed with their pass axes perpendicular to each other. Unpolarised light of intensity I₀ is incident on P₁. A third Polaroid P₃ is placed between P₁ and P₂ with its pass axis at 45° to that of P₁. The intensity of light emerging from P₂ is:", "explanation": "After P₁: intensity = I₀/2 (unpolarised light through a Polaroid). After P₃ (at 45° to P₁): I = (I₀/2)cos²45° = (I₀/2)(1/2) = I₀/4. After P₂ (at 45° to P₃, since P₂ is perpendicular to P₁ and P₃ is at 45° to P₁): I = (I₀/4)cos²45° = (I₀/4)(1/2) = I₀/8.", "correct_answer": "D", "concept_tags": ["malus-law", "crossed-polaroids", "intermediate-polaroid"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-08", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "I₀/2", "is_correct": false}, {"key": "B", "text": "I₀/4", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "I₀/8", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "I₀/2 is only the intensity after the first Polaroid. You must apply Malus''s law at each subsequent Polaroid.", "misconception": "Forgetting to apply Malus''s law at intermediate and final stages"}, {"option_key": "B", "hint": "I₀/4 is the intensity after passing through P₃ but before passing through P₂. One more application of Malus''s law is needed.", "misconception": "Stopping the calculation after the intermediate Polaroid"}, {"option_key": "C", "hint": "Zero would be the result if only P₁ and P₂ (crossed) were present. The intermediate Polaroid P₃ at 45° allows some light to pass through.", "misconception": "Ignoring the effect of the intermediate Polaroid between crossed Polaroids"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Unpolarised light is incident on a Polaroid. The Polaroid is then rotated about the direction of the incident light. The intensity of the transmitted light:", "explanation": "When unpolarised light passes through a Polaroid, the transmitted intensity is always I₀/2, regardless of the orientation of the Polaroid''s pass axis. This is because unpolarised light has vibrations uniformly distributed in all directions perpendicular to propagation. Rotating the Polaroid simply changes which component is transmitted, but the average intensity remains the same at I₀/2.", "correct_answer": "A", "concept_tags": ["polaroid", "unpolarised-light", "rotation-of-polaroid"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-09", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "Remains constant at I₀/2", "is_correct": true}, {"key": "B", "text": "Varies between 0 and I₀", "is_correct": false}, {"key": "C", "text": "Varies between 0 and I₀/2", "is_correct": false}, {"key": "D", "text": "Becomes zero at certain orientations", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Variation between 0 and I₀ occurs only when plane polarised light passes through a rotating analyser (Malus''s law). For unpolarised incident light, the Polaroid output is constant.", "misconception": "Confusing unpolarised light behaviour with polarised light behaviour through a rotating analyser"}, {"option_key": "C", "hint": "There is no variation at all. Unpolarised light has no preferred direction of vibration, so all orientations of the Polaroid give the same result.", "misconception": null}, {"option_key": "D", "hint": "Zero intensity occurs only when plane polarised light is incident on a Polaroid with its pass axis perpendicular to the polarisation direction. Unpolarised light always gives non-zero transmission.", "misconception": "Confusing crossed Polaroid effect with single Polaroid on unpolarised light"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The sky appears blue due to scattering of sunlight by air molecules. The scattered light observed at 90° to the direction of sunlight is:", "explanation": "When sunlight is scattered by small air molecules (Rayleigh scattering), the scattered light is partially polarised. At exactly 90° to the direction of incident sunlight, the scattered light is completely plane polarised. This is because the oscillating electric dipoles induced in air molecules cannot radiate energy along their axis of oscillation, so light scattered at 90° has only one vibration direction.", "correct_answer": "B", "concept_tags": ["polarisation-by-scattering", "rayleigh-scattering", "plane-polarised-light"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-10", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "Unpolarised", "is_correct": false}, {"key": "B", "text": "Completely plane polarised", "is_correct": true}, {"key": "C", "text": "Circularly polarised", "is_correct": false}, {"key": "D", "text": "Elliptically polarised", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The scattered light is not unpolarised. Scattering by molecules introduces polarisation, and at 90° it is fully polarised.", "misconception": "Assuming scattered light retains the same polarisation state as incident light"}, {"option_key": "C", "hint": "Circularly polarised light has two perpendicular components with a 90° phase difference. Scattering does not introduce such a phase relationship.", "misconception": "Confusing different types of polarisation"}, {"option_key": "D", "hint": "Elliptical polarisation also requires a specific phase relationship between perpendicular components. Scattering at 90° produces linearly (plane) polarised light.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Unpolarised light of intensity I₀ passes through three Polaroids. The first Polaroid has its pass axis vertical. The second has its pass axis at 30° to the vertical, and the third has its pass axis at 60° to the vertical. The intensity of light emerging from the third Polaroid is:", "explanation": "After Polaroid 1: I₁ = I₀/2 (unpolarised to polarised). After Polaroid 2 (angle between pass axes = 30°): I₂ = (I₀/2)cos²30° = (I₀/2)(3/4) = 3I₀/8. After Polaroid 3 (angle between pass axis of Polaroid 2 and Polaroid 3 = 60° - 30° = 30°): I₃ = (3I₀/8)cos²30° = (3I₀/8)(3/4) = 9I₀/32.", "correct_answer": "C", "concept_tags": ["malus-law", "multiple-polaroids", "intensity-calculation"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-11", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "I₀/8", "is_correct": false}, {"key": "B", "text": "3I₀/8", "is_correct": false}, {"key": "C", "text": "9I₀/32", "is_correct": true}, {"key": "D", "text": "3I₀/32", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "I₀/8 would result from using 60° as the angle at both Polaroid 2 and Polaroid 3. The angle in Malus''s law is between consecutive pass axes, not from the first.", "misconception": "Using the angle relative to the first Polaroid rather than the previous one"}, {"option_key": "B", "hint": "3I₀/8 is the intensity after the second Polaroid. You still need to apply Malus''s law for the third Polaroid.", "misconception": "Stopping the calculation prematurely"}, {"option_key": "D", "hint": "3I₀/32 results from incorrectly using cos²60° at the second stage and cos²30° at the third stage, or some other error in angles.", "misconception": "Incorrectly assigning angles between consecutive Polaroids"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Light reflected from a water surface (μ = 4/3) is completely polarised. The angle of refraction of the transmitted light is:", "explanation": "For complete polarisation of reflected light, the angle of incidence equals Brewster''s angle iₚ, where tan iₚ = μ = 4/3. At Brewster''s angle, iₚ + r = 90°, so r = 90° - iₚ. Since tan iₚ = 4/3, we get iₚ = tan⁻¹(4/3) ≈ 53.1°. Therefore r = 90° - 53.1° = 36.9° ≈ 37°. Alternatively, since tan iₚ = μ and iₚ + r = 90°, then tan r = 1/μ = 3/4, giving r = tan⁻¹(3/4) ≈ 36.9°.", "correct_answer": "D", "concept_tags": ["brewster-angle", "angle-of-refraction", "complete-polarisation"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-12", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "53°", "is_correct": false}, {"key": "B", "text": "45°", "is_correct": false}, {"key": "C", "text": "30°", "is_correct": false}, {"key": "D", "text": "37°", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "53° is the Brewster''s angle (angle of incidence), not the angle of refraction. At Brewster''s angle, r = 90° - iₚ.", "misconception": "Confusing the angle of incidence with the angle of refraction at Brewster''s angle"}, {"option_key": "B", "hint": "45° would be the refraction angle if the Brewster angle were also 45°, which requires μ = 1. For μ = 4/3, this is not the case.", "misconception": null}, {"option_key": "C", "hint": "30° does not satisfy the relation r = 90° - iₚ for μ = 4/3. The correct refraction angle is 90° - 53° = 37°.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Sound waves in air cannot be polarised.\nReason (R): Polarisation is a phenomenon exclusive to transverse waves, and sound waves in air are longitudinal in nature.", "explanation": "Both the assertion and the reason are correct. Sound waves in air are longitudinal waves where particles oscillate along the direction of propagation. Polarisation requires vibrations perpendicular to the direction of propagation, which is possible only in transverse waves. Since sound in air is longitudinal, it cannot be polarised. The reason correctly explains why the assertion is true.", "correct_answer": "A", "concept_tags": ["polarisation", "transverse-wave", "longitudinal-wave", "sound-waves"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-13", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains the assertion: sound in air is longitudinal, and only transverse waves can be polarised, so sound cannot be polarised.", "misconception": "Failing to recognise the direct causal link between the nature of sound waves and impossibility of polarisation"}, {"option_key": "C", "hint": "The reason is factually correct. Sound in air is indeed longitudinal, and polarisation is indeed exclusive to transverse waves.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct. Sound waves in air are longitudinal and cannot be polarised. This is experimentally verified.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): When unpolarised light is reflected at Brewster''s angle from a glass surface, the reflected and refracted rays are perpendicular to each other.\nReason (R): At Brewster''s angle, the refracted light is completely plane polarised.", "explanation": "The assertion is correct. At Brewster''s angle, iₚ + r = 90°, meaning the reflected and refracted rays are indeed perpendicular. The reason, however, is incorrect. At Brewster''s angle, it is the reflected light (not the refracted light) that is completely plane polarised. The refracted light is only partially polarised. Therefore, A is correct but R is incorrect.", "correct_answer": "C", "concept_tags": ["brewster-angle", "reflected-refracted-perpendicular", "polarisation-by-reflection"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-14", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": true}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Check the reason carefully. At Brewster''s angle, it is the reflected light that is completely polarised, not the refracted light.", "misconception": "Confusing which ray (reflected vs refracted) is completely polarised at Brewster''s angle"}, {"option_key": "B", "hint": "The reason itself contains a factual error. The refracted light at Brewster''s angle is only partially polarised, not completely polarised.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct. The perpendicularity of reflected and refracted rays at Brewster''s angle (iₚ + r = 90°) is a well-established fact.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the phenomena in Column I with their descriptions in Column II:\n\nColumn I:\nA. Malus''s law\nB. Brewster''s law\nC. Double refraction\nD. Optical activity\n\nColumn II:\n1. tan iₚ = μ\n2. I = I₀cos²θ\n3. Rotation of the plane of polarisation by certain substances\n4. Splitting of a light ray into ordinary and extraordinary rays in a crystal", "explanation": "Malus''s law gives the intensity of polarised light after passing through an analyser as I = I₀cos²θ (A-2). Brewster''s law relates the polarising angle to the refractive index as tan iₚ = μ (B-1). Double refraction is the phenomenon where a crystal splits an incident ray into ordinary and extraordinary rays (C-4). Optical activity is the property of certain substances to rotate the plane of polarisation of light passing through them (D-3).", "correct_answer": "B", "concept_tags": ["malus-law", "brewster-law", "double-refraction", "optical-activity"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-15", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "A-1, B-2, C-4, D-3", "is_correct": false}, {"key": "B", "text": "A-2, B-1, C-4, D-3", "is_correct": true}, {"key": "C", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "D", "text": "A-1, B-2, C-3, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps A and B. Malus''s law is I = I₀cos²θ (A-2), and Brewster''s law is tan iₚ = μ (B-1), not the reverse.", "misconception": "Interchanging Malus''s law and Brewster''s law formulas"}, {"option_key": "C", "hint": "This swaps C and D. Double refraction involves splitting into O and E rays (C-4), and optical activity involves rotation of the polarisation plane (D-3).", "misconception": "Confusing double refraction with optical activity"}, {"option_key": "D", "hint": "This has all four matchings incorrect. Both A-B and C-D pairs are swapped compared to the correct matching.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the polarisation methods in Column I with their key features in Column II:\n\nColumn I:\nA. Polarisation by reflection\nB. Polarisation by scattering\nC. Polarisation by selective absorption (Polaroid)\nD. Polarisation by double refraction\n\nColumn II:\n1. Uses dichroic crystals or stretched polymer sheets containing aligned molecules\n2. Produces two refracted rays with mutually perpendicular polarisations inside a birefringent crystal\n3. Completely polarises reflected light when incidence is at Brewster''s angle\n4. Light scattered at 90° to the incident beam is completely plane polarised", "explanation": "Polarisation by reflection completely polarises the reflected light at Brewster''s angle (A-3). Polarisation by scattering produces completely polarised light at 90° to the incident direction (B-4). Polaroids use dichroic materials or aligned polymer molecules for selective absorption (C-1). Double refraction in birefringent crystals produces ordinary and extraordinary rays with mutually perpendicular polarisations (D-2).", "correct_answer": "D", "concept_tags": ["polarisation-by-reflection", "polarisation-by-scattering", "polaroid", "double-refraction"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-16", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-3, B-1, C-4, D-2", "is_correct": false}, {"key": "B", "text": "A-4, B-3, C-1, D-2", "is_correct": false}, {"key": "C", "text": "A-3, B-4, C-2, D-1", "is_correct": false}, {"key": "D", "text": "A-3, B-4, C-1, D-2", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and C. Scattering polarises light at 90° (B-4), not Polaroids. Polaroids use selective absorption (C-1), not scattering.", "misconception": "Confusing polarisation by scattering with selective absorption"}, {"option_key": "B", "hint": "This swaps A and B. Polarisation by reflection occurs at Brewster''s angle (A-3), while scattering polarises at 90° (B-4).", "misconception": null}, {"option_key": "C", "hint": "This swaps C and D. Polaroids use dichroic/aligned molecules (C-1), and double refraction produces O and E rays in birefringent crystals (D-2).", "misconception": "Interchanging Polaroid mechanism with double refraction"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "According to Malus''s law, when polarised light passes through an analyser with its pass axis parallel to the polarisation direction (θ = 0°), the transmitted intensity equals the incident intensity.", "explanation": "This statement is true. According to Malus''s law, I = I₀cos²θ. When θ = 0° (pass axis parallel to polarisation direction), cos 0° = 1, so I = I₀cos²0° = I₀ × 1 = I₀. The full intensity of the polarised light is transmitted.", "correct_answer": "A", "concept_tags": ["malus-law", "parallel-polarisation", "intensity"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-17", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Substituting θ = 0° into Malus''s law gives I = I₀ × cos²0° = I₀ × 1 = I₀, confirming the statement is true.", "misconception": "Incorrectly recalling Malus''s law formula"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "At Brewster''s angle, both the reflected and refracted light are completely plane polarised.", "explanation": "This statement is false. At Brewster''s angle, only the reflected light is completely plane polarised (with vibrations perpendicular to the plane of incidence). The refracted (transmitted) light is only partially polarised because it still contains both components of vibration, though the component in the plane of incidence is enhanced relative to the perpendicular component.", "correct_answer": "B", "concept_tags": ["brewster-angle", "reflected-light-polarisation", "refracted-light-partial-polarisation"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-18", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Only the reflected light is completely polarised at Brewster''s angle. The refracted light is partially polarised, not completely polarised.", "misconception": "Assuming both reflected and refracted rays are fully polarised at Brewster''s angle"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "In a calcite crystal, the phenomenon of double refraction produces two rays: the _____ ray which obeys Snell''s law and the extraordinary ray which does not obey Snell''s law.", "explanation": "When light enters a birefringent (doubly refracting) crystal like calcite, it splits into two rays. The ordinary ray (O-ray) obeys Snell''s law of refraction and travels with the same speed in all directions within the crystal. The extraordinary ray (E-ray) does not obey Snell''s law and its speed varies with direction inside the crystal. Both rays are plane polarised with their vibration directions perpendicular to each other.", "correct_answer": "B", "concept_tags": ["double-refraction", "ordinary-ray", "extraordinary-ray", "calcite"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-19", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "refracted", "is_correct": false}, {"key": "B", "text": "ordinary", "is_correct": true}, {"key": "C", "text": "polarised", "is_correct": false}, {"key": "D", "text": "diffracted", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Both rays are refracted rays. The specific terminology used in double refraction is ''ordinary'' for the ray obeying Snell''s law and ''extraordinary'' for the one that does not.", "misconception": "Using a generic term instead of the specific terminology of double refraction"}, {"option_key": "C", "hint": "Both the ordinary and extraordinary rays are polarised. The blank specifically refers to the ray that obeys Snell''s law, which is called the ordinary ray.", "misconception": null}, {"option_key": "D", "hint": "Diffraction is bending of light around obstacles and is unrelated to double refraction in crystals.", "misconception": "Confusing refraction in crystals with diffraction"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "An engineer is testing the structural integrity of a transparent plastic bridge model using photoelasticity (stress analysis). She places the model between two crossed Polaroids and observes coloured fringe patterns at stress concentration points when white light is used.\n\nUnpolarised light of intensity I₀ is first passed through a polariser. It then passes through the stressed plastic model, which rotates the plane of polarisation by 30°. Finally, the light passes through an analyser whose pass axis is perpendicular to the polariser''s pass axis. What is the intensity of light emerging from the analyser?", "explanation": "After the polariser: I₁ = I₀/2 (unpolarised to polarised). The stressed plastic rotates the polarisation direction by 30°. Since the analyser is perpendicular to the polariser (90° apart), and the polarisation has been rotated by 30°, the angle between the polarisation direction of light entering the analyser and the analyser''s pass axis is 90° - 30° = 60°. Applying Malus''s law: I₂ = I₁cos²60° = (I₀/2)(1/2)² = (I₀/2)(1/4) = I₀/8.", "correct_answer": "C", "concept_tags": ["malus-law", "stress-analysis", "photoelasticity", "crossed-polaroids", "rotation-of-polarisation"], "payload": {"question_id": "cuet-phy-waveopt-polarisation-20", "subtopic": "Polarisation of Light", "topic_name": "Polarisation of Light", "bloom_level": "analyze", "options": [{"key": "A", "text": "I₀/4", "is_correct": false}, {"key": "B", "text": "3I₀/8", "is_correct": false}, {"key": "C", "text": "I₀/8", "is_correct": true}, {"key": "D", "text": "I₀/2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "I₀/4 would result if the angle with the analyser were 45° (cos²45° = 1/2 applied to I₀/2). But the rotation is 30°, making the effective angle 60° with the analyser.", "misconception": "Using the rotation angle directly instead of computing the angle relative to the analyser"}, {"option_key": "B", "hint": "3I₀/8 = (I₀/2)cos²30°. This would be correct if the angle between the rotated polarisation and the analyser were 30°, but it is actually 90° - 30° = 60°.", "misconception": "Using the rotation angle (30°) instead of the angle with the analyser''s pass axis (60°)"}, {"option_key": "D", "hint": "I₀/2 is the intensity just after the first polariser. After the analyser, Malus''s law must be applied with the appropriate angle.", "misconception": "Forgetting to apply Malus''s law at the analyser stage"}]}}]'::jsonb, 'deploy-2026-03-05-b14');

